  WITH DS_MUREX AS
(
    -- MEP 2025-10-24
    SELECT *
    FROM "TMF_SERVICES".MV_CFTC_TR_RECON_COMMON
--    FROM c38491ab.test_common_cftc_REGTR5421
    WHERE
        THD_TRD_CLASS_SRC_NAME LIKE 'IRD%'
		AND THD_TRD_CLASS_SRC_NAME != 'IRD_RTRN_BSK'
		AND NVL(UPI, ' ') NOT LIKE 'Credit%'
)
,BASIS_CONV_MAP AS
(
    SELECT '30/360'        AS INVAL,'A001' AS OUTVAL FROM DUAL UNION ALL
    SELECT 'ACT/360'       AS INVAL,'A004' AS OUTVAL FROM DUAL UNION ALL
    SELECT 'ACT/365.FIXED' AS INVAL,'A005' AS OUTVAL FROM DUAL UNION ALL
    SELECT 'ACT/ACT.ICMA'  AS INVAL,'A006' AS OUTVAL FROM DUAL UNION ALL
    SELECT '30E/360.ISDA'  AS INVAL,'A007' AS OUTVAL FROM DUAL UNION ALL
    SELECT 'ACT/ACT.ISDA'  AS INVAL,'A008' AS OUTVAL FROM DUAL UNION ALL
    SELECT 'ACT/365L'      AS INVAL,'A009' AS OUTVAL FROM DUAL UNION ALL
    SELECT 'ACT/ACT.AFB'   AS INVAL,'A010' AS OUTVAL FROM DUAL UNION ALL
    SELECT '30E/360'       AS INVAL,'A011' AS OUTVAL FROM DUAL UNION ALL
    SELECT 'ACT/ACT.ISMA'  AS INVAL,'A015' AS OUTVAL FROM DUAL UNION ALL
    SELECT 'BUS/252'       AS INVAL,'A018' AS OUTVAL FROM DUAL UNION ALL
    SELECT '1/1'           AS INVAL,'A020' AS OUTVAL FROM DUAL
)
,UPI_ANNA_DSB AS
(
    SELECT
        SYS_VALUE_DATE
        ,UPI_STATUS
        ,UPI_UNIQUE_PRD_ID
        ,UPI_UNDERLYING_ID
        ,NVL(UPI_INT_CODE, ' ') AS UPI_INT_CODE
        ,NVL(UPI_INT_IDX,' ') AS UPI_INT_IDX
        ,NVL(UPI_NOTIONAL_LEG1_CCY,' ') AS UPI_NOTIONAL_LEG1_CCY
        ,NVL(UPI_NOTIONAL_LEG2_CCY,' ') AS UPI_NOTIONAL_LEG2_CCY
        ,NVL(UPI_REFERENCE_RATE_LEG1,' ') AS UPI_REFERENCE_RATE_LEG1
        ,NVL(REGEXP_SUBSTR(UPI_UNDERLYING_INDEX_TERM,'^\d+'),' ') AS UPI_UNDERLYING_INDEX_TERM_VAL
        ,NVL(REGEXP_SUBSTR(UPI_UNDERLYING_INDEX_TERM,'[A-Za-z].*'),' ') AS UPI_UNDERLYING_INDEX_TERM_UNT
        ,NVL(UPI_REFERENCE_RATE_UNIT_LEG1,' ') AS UPI_REFERENCE_RATE_UNIT_LEG1
        ,NVL(UPI_TRANSACTION_TYPE,' ') AS UPI_TRANSACTION_TYPE
        ,NVL(UPI_DELIVERY_TYPE,' ') AS UPI_DELIVERY_TYPE
        ,NVL(UPI_OTHR_FLOAT_RATE_INDX,' ') AS UPI_OTHR_FLOAT_RATE_INDX
        ,NVL(UPI_REFERENCE_RATE_LEG2,' ') AS UPI_REFERENCE_RATE_LEG2
        ,NVL(UPI_REFERENCE_RATE_UNIT_LEG2,' ') AS UPI_REFERENCE_RATE_UNIT_LEG2
        ,NVL(UPI_INDEX_TYPE,' ') AS UPI_INDEX_TYPE
        ,DECODE(UPI_EXERCISE_STYLE,'EURO','European','AMER','American','BERM','Bermudan', ' ') AS UPI_EXERCISE_STYLE
        ,NVL(UPI_OPTION_TYPE,' ') AS UPI_OPTION_TYPE
        ,NVL(UPI_UNDERLYING_INSTR_CODE,' ') AS UPI_UNDERLYING_INSTR_CODE
        ,NVL(UPI_RETURN_OR_PAYOUT_TRIG,' ') AS UPI_RETURN_OR_PAYOUT_TRIG
    FROM "FMODS".TB_UPIFMO_UPI_ANNADSB
    WHERE
        UPI_STATUS IN ('Active','Updated')
        AND SYS_VALUE_DATE = (SELECT MAX(SYS_VALUE_DATE) FROM "FMODS".TB_UPIFMO_UPI_ANNADSB)
)
,UPX_ANNA_DSB AS
(
    SELECT *
    FROM "FMODS".TB_UPXFMO_UPI_ANNADSB_REF_RATE
    WHERE SYS_VALUE_DATE = (SELECT MAX(SYS_VALUE_DATE) FROM "FMODS".TB_UPXFMO_UPI_ANNADSB_REF_RATE)
)
,FINAL_DATA AS
(
    SELECT
        --<GH_Rewrite_Work>
        DMX.REPORTABLE_CFTC,
        DMX.REPORTABLE_CSA,
        --</GH_Rewrite_Work>

        DMX.CLEARED,

        --<GH_Rewrite_Work>
        --DMX.CLEAR_EXCEPTION2,
        CASE
            WHEN DMX.CLEARED IN ('Y', 'I') OR DMX.EMBEDDED_OPT IS NOT NULL OR THD_FAMILY IN('CURR','COM','EQD') OR THD_GROUP IN('BOND','CF','TRS','CF','RTRN','CDS') THEN NULL
            WHEN DMX.THD_REPORTING_PARTY_CA_FLG = 'Y' AND DMX.THD_REPORTING_PARTY_US_FLG = 'Y' AND sub_clearable.CFTC_CLEARABLE = 'Y' THEN
                CASE
                    WHEN DMX.THD_MARGIN_INDICATOR =  'Affiliate' THEN 'AFFL'
                    WHEN DMX.RPY_CLR_EX_END_USR_EXCEPT_FLG_CPTY = 'Y' THEN 'ENDU'
                    WHEN DMX.RPY_CLR_EX_SMALL_BK_EXMPT_FLG_CPTY = 'Y' THEN 'SMBK'
                    WHEN DMX.RPY_CLR_EX_COOP_EXMPT_FLG_CPTY = 'Y' THEN 'COOP'
                    WHEN DMX.RPY_CLR_EX_NO_ACT_LETTER_FLG_CPTY = 'Y' THEN 'NOAL'
                    WHEN DMX.RPY_CLR_EX_OTHER_EXCEPT_FLG_CPTY = 'Y' THEN 'OTHR'
                    ELSE NULL
                END
            ELSE NULL
        END AS CLEAR_EXCEPTION2_CFTC,

        CASE
            WHEN DMX.CLEARED IN ('Y', 'I') OR DMX.EMBEDDED_OPT IS NOT NULL OR THD_FAMILY IN('CURR','COM','EQD') OR THD_GROUP IN('BOND','CF','TRS','CF','RTRN','CDS') THEN NULL
            WHEN DMX.THD_REPORTING_PARTY_CA_FLG = 'Y' AND DMX.THD_REPORTING_PARTY_US_FLG = 'Y' AND sub_clearable.CAN_CLEARABLE = 'Y' THEN
                CASE
                    WHEN DMX.THD_MARGIN_INDICATOR =  'Affiliate' THEN 'AFFL'
                    WHEN DMX.RPY_CLR_EX_END_USR_EXCEPT_FLG_CPTY = 'Y' THEN 'ENDU'
                    WHEN DMX.RPY_CLR_EX_SMALL_BK_EXMPT_FLG_CPTY = 'Y' THEN 'SMBK'
                    WHEN DMX.RPY_CLR_EX_COOP_EXMPT_FLG_CPTY = 'Y' THEN 'COOP'
                    WHEN DMX.RPY_CLR_EX_NO_ACT_LETTER_FLG_CPTY = 'Y' THEN 'NOAL'
                    WHEN DMX.RPY_CLR_EX_OTHER_EXCEPT_FLG_CPTY = 'Y' THEN 'OTHR'
                    ELSE NULL
                END
            WHEN DMX.THD_REPORTING_PARTY_CA_FLG = 'Y' AND NVL(DMX.THD_REPORTING_PARTY_US_FLG,' ') != 'Y' AND sub_clearable.CAN_CLEARABLE = 'Y' THEN
                 CASE
                    WHEN DMX.THD_MARGIN_INDICATOR =  'Affiliate' THEN 'AFFL'
                    WHEN DMX.RPY_CLR_EX_END_USR_EXCEPT_FLG_CPTY = 'Y' THEN 'OTHR'
                    WHEN DMX.RPY_CLR_EX_SMALL_BK_EXMPT_FLG_CPTY = 'Y' THEN 'OTHR'
                    WHEN DMX.RPY_CLR_EX_COOP_EXMPT_FLG_CPTY = 'Y' THEN 'OTHR'
                    WHEN DMX.RPY_CLR_EX_NO_ACT_LETTER_FLG_CPTY = 'Y' THEN 'OTHR'
                    WHEN DMX.RPY_CLR_EX_OTHER_EXCEPT_FLG_CPTY = 'Y' THEN 'OTHR'
                    ELSE NULL
                END
            ELSE NULL
        END AS CLEAR_EXCEPTION2_CSA,
        --</GH_Rewrite_Work>

        DMX.REPORTING_PARTY_LEI,

        DMX.COUNTERPARTY_LEI,

        DMX.PARTY_TYP2,

        DMX.FINANCIAL_ENTITY1,

        DMX.FINANCIAL_ENTITY2,

        CASE
            WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_CF','IRD_FRA','IRD_OSWP','IRD_BOND_FWD','IRD_OPT_OTC') THEN DECODE(DMX.THD_BUY_SELL_IND,'BUY',DMX.REPORTING_PARTY_LEI,'SELL',DMX.COUNTERPARTY_LEI,NULL)
            ELSE NULL
        END AS BUYER,

        CASE
            WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_CF','IRD_FRA','IRD_OSWP','IRD_BOND_FWD','IRD_OPT_OTC')  THEN DECODE(DMX.THD_BUY_SELL_IND,'SELL',DMX.REPORTING_PARTY_LEI,'BUY',DMX.COUNTERPARTY_LEI,NULL)
            ELSE NULL
        END AS SELLER,

        CASE
            WHEN DMX.THD_TRD_QUALIF_VAL = 'SWP' AND DMX.THD_FGT_GRP != 'RTRN' THEN DECODE(DMX.TRP_PAY_RECV_IND_NEAR,'P', DMX.REPORTING_PARTY_LEI,DMX.COUNTERPARTY_LEI)
            ELSE NULL
        END AS PAYER_LEG1,

        CASE
            WHEN DMX.THD_TRD_QUALIF_VAL = 'SWP' AND DMX.THD_FGT_GRP != 'RTRN' THEN DECODE(DMX.TRP_PAY_RECV_IND_FAR,'P',DMX.REPORTING_PARTY_LEI,DMX.COUNTERPARTY_LEI)
            ELSE NULL
        END AS PAYER_LEG2,

        CASE
            WHEN DMX.THD_TRD_QUALIF_VAL = 'SWP' AND DMX.THD_FGT_GRP != 'RTRN' THEN DECODE(DMX.TRP_PAY_RECV_IND_NEAR,'P',DMX.COUNTERPARTY_LEI,DMX.REPORTING_PARTY_LEI)
            ELSE NULL
        END AS RECEIVER_LEG1,

        CASE
            WHEN DMX.THD_TRD_QUALIF_VAL = 'SWP' AND DMX.THD_FGT_GRP != 'RTRN' THEN DECODE(DMX.TRP_PAY_RECV_IND_FAR,'P',DMX.COUNTERPARTY_LEI,DMX.REPORTING_PARTY_LEI)
            ELSE NULL
        END AS RECEIVER_LEG2,

        DMX.FEDERAL_ENTITY2,

        DMX.CUSTOM_BSK_IND,

        DMX.EVENT_ID,

        DMX.EVENT_TIME,

        DMX.CCF_NOTIONAL_LEG1_CFTC_AMT AS NOTIONAL1,

        DMX.CCF_NOTIONAL_LEG2_CFTC_AMT AS NOTIONAL2,

        DMX.CCF_NOTIONAL_LEG1_CFTC_CCY AS CURR1,

        DMX.CCF_NOTIONAL_LEG2_CFTC_CCY AS CURR2,

        CASE
            WHEN DMX.THD_FGT_GRP IN('IRS','CS','CF','OSWP','TRS') THEN
                CASE
                    WHEN DMX.THD_NOTIONAL_SCHEDULE_CODE = 'C' THEN NULL
                    WHEN INSTR(DMX.LIST_REMAIN_CAP_AMT_NEAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT, ',', 1, 17) = 0 THEN DMX.LIST_REMAIN_CAP_AMT_NEAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT
                    ELSE substr(DMX.LIST_REMAIN_CAP_AMT_NEAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT, 1, INSTR(DMX.LIST_REMAIN_CAP_AMT_NEAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT, ',', 1, 17) -1)
                END
            ELSE NULL
        END AS NOTIONAL_AMT_EFFECTI_DATE_LEG1,

        CASE
            WHEN DMX.THD_FGT_GRP IN('IRS','CS','CF','OSWP','TRS') THEN
                CASE
                    WHEN DMX.THD_NOTIONAL_SCHEDULE_CODE = 'C' THEN NULL
                    WHEN INSTR(DMX.LIST_REMAIN_CAP_AMT_FAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT, ',', 1, 17) = 0 THEN DMX.LIST_REMAIN_CAP_AMT_FAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT
                    ELSE substr(DMX.LIST_REMAIN_CAP_AMT_FAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT, 1, INSTR(DMX.LIST_REMAIN_CAP_AMT_FAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT, ',', 1, 17) -1)
                END
            ELSE NULL
        END AS NOTIONAL_AMT_EFFECTI_DATE_LEG2,

        CASE
            WHEN DMX.THD_FGT_GRP IN('IRS','CS','CF','OSWP','TRS') THEN
                CASE
                    WHEN DMX.THD_NOTIONAL_SCHEDULE_CODE = 'C' THEN NULL
                    WHEN INSTR(DMX.LIST_PERIOD_START_NEAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT, ',', 1, 17) = 0 THEN DMX.LIST_PERIOD_START_NEAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT
                    ELSE substr(DMX.LIST_PERIOD_START_NEAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT, 1, INSTR(DMX.LIST_PERIOD_START_NEAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT, ',', 1, 17) -1)
                END
            ELSE NULL
        END AS EFFECTI_DATE_NOTIONAL_AMT_LEG1,

        CASE
            WHEN DMX.THD_FGT_GRP IN('IRS','CS','CF','OSWP','TRS') THEN
                CASE
                    WHEN DMX.THD_NOTIONAL_SCHEDULE_CODE = 'C' THEN NULL
                    WHEN INSTR(DMX.LIST_PERIOD_START_FAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT, ',', 1, 17) = 0 THEN DMX.LIST_PERIOD_START_FAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT
                    ELSE substr(DMX.LIST_PERIOD_START_FAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT, 1, INSTR(DMX.LIST_PERIOD_START_FAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT, ',', 1, 17) -1)
                END
            ELSE NULL
        END AS EFFECTI_DATE_NOTIONAL_AMT_LEG2,

        CASE
            WHEN DMX.THD_FGT_GRP IN('IRS','CS','CF','OSWP','TRS') THEN
                CASE
                    WHEN DMX.THD_NOTIONAL_SCHEDULE_CODE = 'C' OR NEXT_START_NEAR = CURRENT_END_NEAR OR NEXT_START_NEAR IS NULL THEN NULL
                    WHEN INSTR(DMX.LIST_PERIOD_END_NEAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT, ',', 1, 17) = 0 THEN DMX.LIST_PERIOD_END_NEAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT
                    ELSE substr(DMX.LIST_PERIOD_END_NEAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT, 1, INSTR(DMX.LIST_PERIOD_END_NEAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT, ',', 1, 17) -1)
                END
            ELSE NULL
        END AS END_NOTIONAL_AMOUNT_LEG1,

        CASE
            WHEN DMX.THD_FGT_GRP IN('IRS','CS','CF','OSWP','TRS') THEN
                CASE
                    WHEN DMX.THD_NOTIONAL_SCHEDULE_CODE = 'C' OR NEXT_START_FAR = CURRENT_END_FAR OR NEXT_START_FAR IS NULL THEN NULL
                    WHEN INSTR(DMX.LIST_PERIOD_END_FAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT, ',', 1, 17) = 0 THEN DMX.LIST_PERIOD_END_FAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT
                    ELSE substr(DMX.LIST_PERIOD_END_FAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT, 1, INSTR(DMX.LIST_PERIOD_END_FAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT, ',', 1, 17) -1)
                END
            ELSE NULL
        END AS END_NOTIONAL_AMOUNT_LEG2,

        CAST(NULL AS VARCHAR2(1 BYTE)) AS CALL_AMOUNT_LEG1,

        CAST(NULL AS VARCHAR2(1 BYTE)) AS CALL_AMOUNT_LEG2,

        CAST(NULL AS VARCHAR2(1 BYTE)) AS CALL_CURR_LEG1,

