		CAST(NULL AS VARCHAR2(1 BYTE)) AS UNDERLYING_ASSET_NAME,

        --<GH_Rewrite_Work>
        -- Ces champs ne peuvent plus  tre "communs" car utilisent des champs par asset-class dans leur formule! Molson salue les vrais!
--        DMX.MASTER_AGREEMENT_TYPE,
--		DMX.MASTER_AGREEMENT_VERSION,
        sub_agreement_type.MASTER_AGREEMENT_TYPE,
        DECODE(sub_agreement_type.MASTER_AGREEMENT_TYPE,'ISDA',DMX.MLG_VERSION,NULL) AS MASTER_AGREEMENT_VERSION,
		--<GH_Rewrite_Work>

		DMX.COLLATERALIZED,

		DMX.LOCAL_CPT_JURISDICTION2,

		DMX.INTER_AFFILIATE,

		DMX.BROKER_TYPE,

		DMX.BROKER_ID,

		DMX.EXECUTION_VENUE,

		DMX.EXECUTION_VENUE_TYPE,

        --<GH_Rewrite_Work>
        --'Rates' AS UPI_ASSET_CLASS,
        sub_upi_fields.UPI_ASSET_CLASS,

--        CASE
--           WHEN DMX.THD_FGT_GRP IN ('OPT', 'OSWP', 'CF') THEN 'Option'
--           WHEN DMX.THD_FGT_GRP IN ('IRS', 'CS') THEN 'Swap'
--           WHEN DMX.THD_FGT_GRP = 'FRA' OR DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_BOND_FWD' THEN 'Forward'
--           ELSE NULL
--        END AS UPI_INSTRUMENT_TYPE,
        sub_upi_fields.UPI_INSTRUMENT_TYPE,

        'UPI' AS UPI_LEVEL,

--        CASE
--            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_BOND_FWD' THEN 'Debt'
--            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_OPT_OTC' THEN 'Debt_Option'
--            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_FRA' THEN 'FRA_Index'
--            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_OSWP' THEN 'Swaption'
--            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CF' AND DMX.TRO_PAYOUT_AMT = 0 THEN 'CapFloor'
--            WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_CF','IRD_TRS') THEN 'Non_Standard'
--            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CS' THEN
--                CASE
--                    WHEN DMX.THD_ZERO_COUPON_IND = 'Y' THEN 'Cross_Currency_Zero_Coupon'
--                    WHEN DMX.TRP_FIX_FLOAT_RATE_IND_NEAR = 'F' AND DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'F' THEN 'Cross_Currency_Fixed_Fixed'
--                    WHEN DMX.TRP_FIX_FLOAT_RATE_IND_NEAR = 'V' AND DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'V' THEN 'Cross_Currency_Basis'
--                    WHEN COALESCE(DMX.TRP_FX_UNDERL_ISO_CCY_CODE_NEAR,DMX.TRP_FX_UNDERL_ISO_CCY_CODE_FAR,' ') NOT IN(DMX.TRP_COM_CCY_CODE_NEAR,DMX.TRP_COM_CCY_CODE_FAR) THEN 'Cross_Currency_Fixed_Float_NDS'
--                    ELSE'Cross_Currency_Fixed_Float'
--                END
--            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_IRS' THEN sub_upi_product_IRS_rule.UPI_PRODUCT
--            ELSE NULL
--        END AS UPI_PRODUCT,
        sub_upi_fields.UPI_PRODUCT,
        --</GH_Rewrite_Work>

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_ADD_SUB_PRODUCT,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_BASE_PRODUCT,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_CONTRACT_SPEC,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_DEBT_SENIORITY,

        sub_upi_delivery_type.UPI_DELIVERY_TYPE AS UPI_DELIVERY_TYPE,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_INSTR_ISIN,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_INSTR_LEI,

        sub_upi_notional_curr.UPI_NOTIONAL_CURR,

        --<GH_Rewrite_Work>
--        CASE
--            WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS','IRD_TRS') THEN sub_notional_schedule.NOTIONAL_SCHEDULE
--            ELSE NULL
--        END AS UPI_NOTIONAL_SCHEDULE,
        sub_upi_fields.UPI_NOTIONAL_SCHEDULE,
        --</GH_Rewrite_Work>

        sub_upi_option_type.UPI_OPTION_EXERCISE_STYLE,

        sub_upi_option_type.UPI_OPTION_TYPE,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_OTHR_ADD_SUB_PRODUCT,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_OTHR_BASE_PRODUCT,

        --<GH_Rewrite_Work>
        --DECODE(sub_flipped_cols_except_currency.UPI_OTHR_LEG_REF_RATE,'~~~','OTHER',sub_flipped_cols_except_currency.UPI_OTHR_LEG_REF_RATE) AS UPI_OTHR_LEG_REF_RATE,
        sub_upi_fields.UPI_OTHR_LEG_REF_RATE,
        --</GH_Rewrite_Work>

        NULLIF(sub_flipped_cols_except_currency.UPI_OTHR_LEG_REF_RATE,'~~~')  AS UPI_OTHR_LEG_REF_RATE_DISPLAY,

        sub_flipped_cols_except_currency.UPI_OTHR_LEG_REF_RATE_TRM_UNT,

        sub_flipped_cols_except_currency.UPI_OTHR_LEG_REF_RATE_TRM_VAL,

        CAST(NULL AS VARCHAR2(1 BYTE)) AS UPI_OTHR_LEG_UNDERLIER_CHAR,

        sub_upi_notional_curr.UPI_OTHR_LEG_NOTIONAL_CURR,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_OTHR_REF_RATE,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_OTHR_SUB_PRODUCT,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_OTHER_UNDERLIER_CHAR,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_PLACE_SETTLEMENT,

        --<GH_Rewrite_Work>
        --DECODE(sub_flipped_cols_except_currency.UPI_REF_RATE,'~~~','OTHER',sub_flipped_cols_except_currency.UPI_REF_RATE) AS UPI_REF_RATE,
        sub_upi_fields.UPI_REF_RATE,
        --</GH_Rewrite_Work>

        NULLIF(sub_flipped_cols_except_currency.UPI_REF_RATE,'~~~')  AS UPI_REF_RATE_DISPLAY,

        sub_flipped_cols_except_currency.UPI_REF_RATE_TRM_UNT,

        sub_flipped_cols_except_currency.UPI_REF_RATE_TRM_VAL,

        DECODE(DMX.THD_TRD_CLASS_SRC_NAME,'IRD_BOND_FWD','Forward price of underlying instrument',NULL) AS UPI_RETURN_PAYOUT_TRIGGER,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_SETTLEMENT_CURR,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_SUB_PRODUCT,

        CASE
            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_BOND_FWD' THEN 'Single'
            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CF' AND (NVL(DMX.TRO_PAYOUT_AMT,0) != 0 OR DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE '%Digital%' OR DMX.THD_TYPOLOGY_DESC LIKE '%Digital%') THEN 'Single'
            ELSE NULL
        END AS UPI_UNDERLIER_CHAR,

        CASE
            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CS' THEN
                CASE
                    WHEN DMX.TRP_FIX_FLOAT_RATE_IND_NEAR = 'F' AND DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'F' THEN 'Fixed - Fixed'
                    WHEN DMX.TRP_FIX_FLOAT_RATE_IND_NEAR = 'V' AND DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'V' THEN 'Basis Swap (Float - Float)'
                    WHEN DMX.THD_ZERO_COUPON_IND = 'Y' THEN 'Zero Coupon'
                    ELSE 'Fixed - Floating'
                END
            WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_OSWP') THEN
                CASE
                    WHEN DMX.TRP_FIX_FLOAT_RATE_IND_NEAR = 'F' AND DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'F' THEN 'Fixed - Fixed'
                    WHEN DMX.TRP_FIX_FLOAT_RATE_IND_NEAR = 'V' AND DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'V' THEN
                        CASE
                            WHEN UPPER(DMX.THD_IDX_CLASS_SIDE1) LIKE '%OIS%' OR UPPER(DMX.THD_IDX_CLASS_SIDE2) LIKE '%OIS%' OR
                                 UPPER(DMX.TRP_LEG_MAIN_IDX_VAL_NEAR) LIKE '%O/N%' OR UPPER(DMX.TRP_LEG_MAIN_IDX_VAL_NEAR) LIKE '%0/N%' OR
                                 UPPER(DMX.TRP_LEG_MAIN_IDX_VAL_FAR) LIKE '%O/N%' OR UPPER(DMX.TRP_LEG_MAIN_IDX_VAL_FAR) LIKE '%0/N%' OR
                                 UPPER(DMX.TRP_UNDERL_SECUR_LABEL_NEAR) LIKE '%O/N%' OR UPPER(DMX.TRP_UNDERL_SECUR_LABEL_NEAR) LIKE '%0/N%' OR
                                 UPPER(DMX.TRP_UNDERL_SECUR_LABEL_FAR) LIKE '%O/N%' OR UPPER(DMX.TRP_UNDERL_SECUR_LABEL_FAR) LIKE '%0/N%' THEN 'Overnight Index Swap (OIS)'
                            ELSE 'Basis Swap (Float - Float)'
                        END
                    WHEN DMX.THD_ZERO_COUPON_IND = 'Y' THEN 'Zero Coupon'
                    WHEN UPPER(DMX.THD_IDX_CLASS_SIDE1) LIKE '%OIS%' OR UPPER(DMX.THD_IDX_CLASS_SIDE2) LIKE '%OIS%' OR
                         UPPER(DMX.TRP_LEG_MAIN_IDX_VAL_NEAR) LIKE '%O/N%' OR UPPER(DMX.TRP_LEG_MAIN_IDX_VAL_NEAR) LIKE '%0/N%' OR
                         UPPER(DMX.TRP_LEG_MAIN_IDX_VAL_FAR) LIKE '%O/N%' OR UPPER(DMX.TRP_LEG_MAIN_IDX_VAL_FAR) LIKE '%0/N%' OR
                         UPPER(DMX.TRP_UNDERL_SECUR_LABEL_NEAR) LIKE '%O/N%' OR UPPER(DMX.TRP_UNDERL_SECUR_LABEL_NEAR) LIKE '%0/N%' OR
                         UPPER(DMX.TRP_UNDERL_SECUR_LABEL_FAR) LIKE '%O/N%' OR UPPER(DMX.TRP_UNDERL_SECUR_LABEL_FAR) LIKE '%0/N%' THEN 'Overnight Index Swap (OIS)'
                    ELSE 'Fixed - Floating'
                END
            WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_BOND_FWD','IRD_OPT_BOND') THEN 'Other'
            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_FRA' THEN 'Interest Rate Index'
            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CF' THEN
                CASE
                    WHEN NVL(DMX.TRO_PAYOUT_AMT,0) != 0 OR DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE '%Dig%' THEN 'Option'
                    ELSE 'Other'
                END
            ELSE NULL
        END AS UPI_UNDRLNG_ASSET_TYPE,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_UNDRLNG_CRD_INDX_SERIES,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_UNDRLNG_CRD_INDX_VERSION,

        CASE
            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CF' AND DMX.TRO_PAYOUT_AMT = 0 AND NVL(DMX.THD_CONTRCT_TYPOLOGY_VAL, ' ') NOT LIKE '%Dig%' AND TRIM(sub_underlier_id.UNDERLIER_ID_LEG1) IS NOT NULL THEN NVL(upx_leg1.UPX_RATES_CODE,'OTHER') --DMX.THD_ISDA_NEAR_LEG_REF_CODE_VAL
            ELSE NULL
        END AS UPI_UNDRLNG_INSTR_INDX,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_UNDRLNG_INSTR_INDX_PROP,

        sub_freq_adjusted.UPI_UNDRLNG_INSTR_TERM_UNT,

        sub_freq_adjusted.UPI_UNDRLNG_INSTR_TERM_VAL,

        CASE
            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_TRS' AND TRP_FIX_FLOAT_RATE_IND_FAR = 'V' THEN
                CASE
                    WHEN TRP_LEG_MAIN_IDX_VAL_FAR LIKE '%_%' THEN RIN_ISIN_ID_MAIN_IDX_LEFT_UNDERSCORE_NEAR
                    ELSE RIN_ISIN_ID_MAIN_IDX_LEFT_UNDERSCORE_FAR
                END
            WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_BOND_FWD','IRD_OPT_OTC') THEN RIN_ISIN_ID_INSTR
            ELSE NULL
        END AS UPI_UNDRLNG_INSTR_ISIN,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_UNDRLNG_INSTR_LEI,

        DMX.THD_DSB_UNDERLIER_LABEL AS UPI_UNDRLNG_INSTR_UPI,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_UNDRLNG_ISSUER_TYPE,

        CASE
            WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_OSWP','IRD_OPT_OTC') THEN 'Vanilla'
            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CF' THEN DECODE(DMX.TRO_PAYOUT_AMT,0,'Other','Digital (Binary)')
            ELSE NULL
        END AS UPI_VALUATION_METHOD_TRIGGER,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_LAST_UPDATE_DATE_TIME,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_STATUS,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_STATUS_REASON,

        DECODE(sub_upi_delivery_type.UPI_DELIVERY_TYPE,'CASH','Cash','PHYS','Physical','OPTL','Elect at Exercise',NULL) AS UPI_CFI_DELIVERY_TYPE,

        TRIM('-' FROM sub_upi_option_type.UPI_OPTION_EXERCISE_STYLE || '-' || DECODE(sub_upi_option_type.UPI_OPTION_TYPE,'CALL','Call','PUTO','Put','OPTL','Chooser',NULL)) AS UPI_CFI_OPTION_STYLE_TYPE,

        DMX.THD_CFI_INSTR_ID AS UPI_CLASSIFICATION_TYPE,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_SHORT_NAME,

        CASE
            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CS' THEN  'Multiple Currency'
            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_IRS' THEN  'Single Currency'
            ELSE NULL
        END AS UPI_SINGLE_MULTI_CURR,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_UNDERLIER_NAME,

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_FURTHER_GROUPING,

        DMX.THD_DSB_UPI AS UPI_DSB_UPI,

        CASE
            WHEN INSTR(sub_oth_fields.OTH_PAYMENT_PAYER_TYPE,',',1,18) = 0 THEN sub_oth_fields.OTH_PAYMENT_PAYER_TYPE
            ELSE SUBSTR(sub_oth_fields.OTH_PAYMENT_PAYER_TYPE,1,INSTR(sub_oth_fields.OTH_PAYMENT_PAYER_TYPE,',',1,18)-1)
        END AS OTH_PAYMENT_PAYER_TYPE,

        CASE
            WHEN INSTR(sub_oth_fields.OTH_PAYMENT_RECEIVER_TYPE,',',1,18) = 0 THEN sub_oth_fields.OTH_PAYMENT_RECEIVER_TYPE
            ELSE SUBSTR(sub_oth_fields.OTH_PAYMENT_RECEIVER_TYPE,1,INSTR(sub_oth_fields.OTH_PAYMENT_RECEIVER_TYPE,',',1,18)-1)
        END AS OTH_PAYMENT_RECEIVER_TYPE,

		sub_upi_product_IRS_rule.UPI_PRODUCT AS UPI_PRODUCT_IRS_RULE,

        DMX.THD_TRD_CLASS_SRC_NAME,

        sub_notional_schedule.NOTIONAL_SCHEDULE,

        sub_freq_adjusted.FLOAT_RESET_FREQUENCY_LEG1 AS FLOAT_RESET_FREQUENCY_LEG1_NO_FGT,

        sub_freq_adjusted.FLOAT_RESET_FREQUENCY_LEG2 AS FLOAT_RESET_FREQUENCY_LEG2_NO_FGT,

        sub_freq_adjusted.FLOAT_RESET_FREQ_MULTI_LEG1 AS FLOAT_RESET_FREQ_MULTI_LEG1_NO_FGT,

        sub_freq_adjusted.FLOAT_RESET_FREQ_MULTI_LEG2 AS FLOAT_RESET_FREQ_MULTI_LEG2_NO_FGT,

        upx_leg1.UPX_RATES_CODE,

        upx_leg2.UPX_RATES_CODE as UPX_RATES_CODE2,

        sub_settlement_type.SETTLEMENT_TYPE,

        THD_DLV_MODE_VAL

        --<GH_Rewrite_Work>
        ,DMX.LEVEL_RPT

        ,DMX.TP2_IND_PROVINCE

        ,CASE
            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CF' AND DMX.THD_PRICE_SCHEDULE_CODE = 'Y' THEN
                CASE
                    WHEN INSTR(DMX.LIST_PERIOD_START_NEAR_INT_CPN_CURRENT_OR_FUTURE,';',1,23) = 0 THEN DMX.LIST_PERIOD_START_NEAR_INT_CPN_CURRENT_OR_FUTURE
                    ELSE SUBSTR(DMX.LIST_PERIOD_START_NEAR_INT_CPN_CURRENT_OR_FUTURE,1,INSTR(DMX.LIST_PERIOD_START_NEAR_INT_CPN_CURRENT_OR_FUTURE,';',1,23)-1)
                END
            ELSE NULL
        END AS EFFECTI_DATE_STRIKE

        ,CASE
            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CF' AND DMX.THD_PRICE_SCHEDULE_CODE = 'Y' THEN
                CASE
                    WHEN REGEXP_SUBSTR(DMX.LIST_PERIOD_END_NEAR_INT_CPN_CURRENT_OR_FUTURE,'[^;]+',1,1) = REGEXP_SUBSTR(DMX.LIST_PERIOD_START_NEAR_INT_CPN_CURRENT_OR_FUTURE,'[^;]+',1,2) OR REGEXP_SUBSTR(DMX.LIST_PERIOD_START_NEAR_INT_CPN_CURRENT_OR_FUTURE,'[^;]+',1,2) IS NULL THEN NULL
                    WHEN INSTR(DMX.LIST_PERIOD_END_NEAR_INT_CPN_CURRENT_OR_FUTURE,';',1,23) = 0 THEN DMX.LIST_PERIOD_END_NEAR_INT_CPN_CURRENT_OR_FUTURE
                    ELSE SUBSTR(DMX.LIST_PERIOD_END_NEAR_INT_CPN_CURRENT_OR_FUTURE,1,INSTR(DMX.LIST_PERIOD_END_NEAR_INT_CPN_CURRENT_OR_FUTURE,';',1,23)-1)
                END
            ELSE NULL
        END AS END_NOTIONAL_STRIKE

        ,CASE
            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CF' AND DMX.THD_PRICE_SCHEDULE_CODE = 'Y' THEN
                CASE
                    WHEN INSTR(DMX.LIST_PERIOD_STRIKE_DIV100_NEAR_INT_CPN_CURRENT_OR_FUTURE,';',1,23) = 0 THEN DMX.LIST_PERIOD_STRIKE_DIV100_NEAR_INT_CPN_CURRENT_OR_FUTURE
                    ELSE SUBSTR(DMX.LIST_PERIOD_STRIKE_DIV100_NEAR_INT_CPN_CURRENT_OR_FUTURE,1,INSTR(DMX.LIST_PERIOD_STRIKE_DIV100_NEAR_INT_CPN_CURRENT_OR_FUTURE,';',1,23)-1)
                END
            ELSE NULL
        END AS STRIKE_SCHEDULE

        ,sub_underlier_id_othr.UNDERLIER_ID_OTHR_LEG1

        ,sub_underlier_id_othr.UNDERLIER_ID_OTHR_LEG2

        ,CASE
            WHEN TRIM(sub_underlier_id_othr.UNDERLIER_ID_OTHR_LEG1) IS NOT NULL THEN 'External'
            ELSE NULL
        END AS UNDERLYING_PRICE_SRC_LEG1

        ,CASE
            WHEN TRIM(sub_underlier_id_othr.UNDERLIER_ID_OTHR_LEG2) IS NOT NULL THEN 'External'
            ELSE NULL
        END AS UNDERLYING_PRICE_SRC_LEG2

        ,CASE
            WHEN TRIM(sub_underlier_id_othr.UNDERLIER_ID_OTHR_LEG1) IS NOT NULL THEN 'ISDAFRONamingConvention'
            ELSE NULL
        END AS UNDERLIER_ID_OTHR_SRC_LEG1

        ,CASE
            WHEN TRIM(sub_underlier_id_othr.UNDERLIER_ID_OTHR_LEG2) IS NOT NULL THEN 'ISDAFRONamingConvention'
            ELSE NULL
        END AS UNDERLIER_ID_OTHR_SRC_LEG2,

        CAST(NULL AS VARCHAR2 (1 BYTE)) AS UNDERLYING_CRYPTO_LEG1,
        CAST(NULL AS VARCHAR2 (1 BYTE)) AS UNDERLYING_CRYPTO_LEG2,
        CAST(NULL AS VARCHAR2 (1 BYTE)) AS CUSTOM_BSK_CODE,
        CAST(NULL AS VARCHAR2 (1 BYTE)) AS CUSTOM_BSK_CONST_ID,
        CAST(NULL AS VARCHAR2 (1 BYTE)) AS CUSTOM_BSK_CONST_ID_SRC,
        CAST(NULL AS VARCHAR2 (1 BYTE)) AS CUSTOM_BSK_CONST_NB_UNIT,
        CAST(NULL AS VARCHAR2 (1 BYTE)) AS CUSTOM_BSK_CONST_UNIT_MEAS,

    --</GH_Rewrite_Work>

    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
    -- <Eric Change Canada Rewrite>
    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS EFFECTI_DATE_NOTIONAL_QTY_LEG1,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS EFFECTI_DATE_NOTIONAL_QTY_LEG2,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS END_NOTIONAL_QTY_LEG1,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS END_NOTIONAL_QTY_LEG2,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS NOTIONAL_QTY_EFFECTI_DATE_LEG1,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS NOTIONAL_QTY_EFFECTI_DATE_LEG2,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS EFFECTI_DATE_PRICE,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS END_NOTIONAL_PRICE,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS PRICE_SCHEDULE,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UNDERLYING_ASSET_PLTF_LEG1,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UNDERLYING_ASSET_PLTF_LEG2

    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
    -- </Eric Change Canada Rewrite>
    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!



    FROM
        DS_MUREX DMX
        CROSS APPLY
        (
            SELECT
                CASE
                    WHEN DMX.THD_TRD_QUALIF_VAL='SWP' AND DMX.THD_TRD_CLASS_SRC_NAME NOT LIKE '%RTRN%'
                         AND
                         (
                            (DMX.IS_MULTIPHASE='N' AND DMX.TRP_FIX_FLOAT_RATE_IND_NEAR='F')
                            OR (DMX.IS_MULTIPHASE='Y' AND TRIM(DMX.MLT_INDEX_LABEL_SIDE1) IS NULL)
                         ) THEN
                            CASE
                                WHEN DMX.CNT_FFL_FLOW_PYMT_DATE_NEAR_INT=1 OR DMX.THD_ZERO_COUPON_IND='Y' THEN 'EXPI'

                                WHEN UPPER(DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_PAYM_PERIOD_UNIT_SIDE1,DMX.TRP_LEG_SWAP_FREQ_VAL_NEAR)) LIKE '%Y%' OR
                                     UPPER(DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_PAYM_PERIOD_UNIT_SIDE1,DMX.TRP_LEG_SWAP_FREQ_VAL_NEAR)) LIKE '%YEAR%' THEN'YEAR'

                                WHEN UPPER(DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_PAYM_PERIOD_UNIT_SIDE1,DMX.TRP_LEG_SWAP_FREQ_VAL_NEAR)) LIKE '%M%' OR
                                     UPPER(DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_PAYM_PERIOD_UNIT_SIDE1,DMX.TRP_LEG_SWAP_FREQ_VAL_NEAR)) LIKE '%MONTH%' OR
                                     UPPER(DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_PAYM_PERIOD_UNIT_SIDE1,DMX.TRP_LEG_SWAP_FREQ_VAL_NEAR)) LIKE '%QUARTER%' OR
                                     UPPER(DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_PAYM_PERIOD_UNIT_SIDE1,DMX.TRP_LEG_SWAP_FREQ_VAL_NEAR)) LIKE '%SEMESTER%' THEN 'MNTH'

                                WHEN UPPER(DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_PAYM_PERIOD_UNIT_SIDE1,DMX.TRP_LEG_SWAP_FREQ_VAL_NEAR)) LIKE '%W%' OR
                                     UPPER(DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_PAYM_PERIOD_UNIT_SIDE1,DMX.TRP_LEG_SWAP_FREQ_VAL_NEAR)) LIKE '%WEEK%' THEN 'WEEK'

                                WHEN UPPER(DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_PAYM_PERIOD_UNIT_SIDE1,DMX.TRP_LEG_SWAP_FREQ_VAL_NEAR)) LIKE '%D%' OR
