                CASE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CF' AND DMX.TRO_PAYOUT_AMT = 0 AND NVL(DMX.THD_CONTRCT_TYPOLOGY_VAL, ' ') NOT LIKE '%Dig%' THEN NULL
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS','IRD_TRS', 'IRD_CF') AND DMX.THD_FIX_FLOAT_RATE_IND = 'V' THEN
                        CASE
                            WHEN NVL(DMX.TRP_SINGLE_PERIOD_IND_NEAR,DMX.TRO_SINGLE_PERIOD_IND) = 'Y' THEN DMX.ELAPSED_FREQ
                            ELSE
                                CASE
                                    WHEN UPPER(NVL(DMX.TRP_LEG_SWAP_FREQ_VAL_NEAR,DMX.TRO_LEG_FIX_FREQ_VAL)) LIKE '%Y%' THEN 'YEAR'
                                    WHEN UPPER(NVL(DMX.TRP_LEG_SWAP_FREQ_VAL_NEAR,DMX.TRO_LEG_FIX_FREQ_VAL)) LIKE '%M%' THEN 'MNTH'
                                    WHEN UPPER(NVL(DMX.TRP_LEG_SWAP_FREQ_VAL_NEAR,DMX.TRO_LEG_FIX_FREQ_VAL)) LIKE '%W%' THEN 'WEEK'
                                    WHEN UPPER(NVL(DMX.TRP_LEG_SWAP_FREQ_VAL_NEAR,DMX.TRO_LEG_FIX_FREQ_VAL)) LIKE '%D%' THEN 'DAYS'
                                    ELSE NULL
                                END
                        END
                    ELSE NULL
                END AS UPI_REF_RATE_TRM_UNT_UNADJST,
                CASE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CF' AND DMX.TRO_PAYOUT_AMT = 0 AND NVL(DMX.THD_CONTRCT_TYPOLOGY_VAL, ' ') NOT LIKE '%Dig%' THEN NULL
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS','IRD_TRS', 'IRD_CF') AND DMX.THD_FIX_FLOAT_RATE_IND = 'V' THEN
                        CASE
                            WHEN NVL(DMX.TRP_SINGLE_PERIOD_IND_NEAR,DMX.TRO_SINGLE_PERIOD_IND) = 'Y' THEN TO_CHAR(DMX.ELAPSED_CALC)
                            ELSE REGEXP_SUBSTR(NVL(DMX.TRP_LEG_SWAP_FREQ_VAL_NEAR,DMX.TRO_LEG_FIX_FREQ_VAL),'^\d+')
                        END
                    ELSE NULL
                END AS UPI_REF_RATE_TRM_VAL_UNADJST,
                CASE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS','IRD_TRS', 'IRD_CF') AND DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'V' THEN
                        CASE
                            WHEN DMX.TRP_SINGLE_PERIOD_IND_FAR = 'Y' THEN TO_CHAR(DMX.ELAPSED_CALC)
                            ELSE REGEXP_SUBSTR(DMX.TRP_LEG_SWAP_FREQ_VAL_FAR,'^\d+')
                        END
                    ELSE NULL
                END AS UPI_OTHR_LEG_REF_RATE_TRM_VAL_UNADJST
            FROM DUAL
        ) sub_freq_unadjst
        CROSS APPLY
        (
            SELECT
                CASE
                    WHEN sub_freq_unadjst.FIX_PMT_FREQ_LEG1_UNADJST='MNTH' AND sub_freq_unadjst.FIX_PMT_FREQ_MULTI_LEG1_UNADJST='12' THEN 'YEAR'
                    WHEN sub_freq_unadjst.FIX_PMT_FREQ_LEG1_UNADJST='DAIL' AND sub_freq_unadjst.FIX_PMT_FREQ_MULTI_LEG1_UNADJST='7' THEN 'WEEK'
                    ELSE sub_freq_unadjst.FIX_PMT_FREQ_LEG1_UNADJST
                END AS FIX_PMT_FREQ_LEG1,
                CASE
                    WHEN sub_freq_unadjst.FIX_PMT_FREQ_LEG1_UNADJST='MNTH' AND sub_freq_unadjst.FIX_PMT_FREQ_MULTI_LEG1_UNADJST='12' THEN '1'
                    WHEN sub_freq_unadjst.FIX_PMT_FREQ_LEG1_UNADJST='DAIL' AND sub_freq_unadjst.FIX_PMT_FREQ_MULTI_LEG1_UNADJST='7' THEN '1'
                    ELSE sub_freq_unadjst.FIX_PMT_FREQ_MULTI_LEG1_UNADJST
                END AS FIX_PMT_FREQ_MULTI_LEG1,

                CASE
                    WHEN sub_freq_unadjst.FIX_PMT_FREQ_LEG2_UNADJST='MNTH' AND sub_freq_unadjst.FIX_PMT_FREQ_MULTI_LEG2_UNADJST='12' THEN 'YEAR'
                    WHEN sub_freq_unadjst.FIX_PMT_FREQ_LEG2_UNADJST='DAIL' AND sub_freq_unadjst.FIX_PMT_FREQ_MULTI_LEG2_UNADJST='7' THEN 'WEEK'
                    ELSE sub_freq_unadjst.FIX_PMT_FREQ_LEG2_UNADJST
                END AS FIX_PMT_FREQ_LEG2,
                CASE
                    WHEN sub_freq_unadjst.FIX_PMT_FREQ_LEG2_UNADJST='MNTH' AND sub_freq_unadjst.FIX_PMT_FREQ_MULTI_LEG2_UNADJST='12' THEN '1'
                    WHEN sub_freq_unadjst.FIX_PMT_FREQ_LEG2_UNADJST='DAIL' AND sub_freq_unadjst.FIX_PMT_FREQ_MULTI_LEG2_UNADJST='7' THEN '1'
                    ELSE sub_freq_unadjst.FIX_PMT_FREQ_MULTI_LEG2_UNADJST
                END AS FIX_PMT_FREQ_MULTI_LEG2,

                CASE
                    WHEN sub_freq_unadjst.FLOAT_PMT_FREQ_LEG1_UNADJST='MNTH' AND sub_freq_unadjst.FLOAT_PMT_FREQ_MULTI_LEG1_UNADJST='12' THEN 'YEAR'
                    WHEN sub_freq_unadjst.FLOAT_PMT_FREQ_LEG1_UNADJST='DAIL' AND sub_freq_unadjst.FLOAT_PMT_FREQ_MULTI_LEG1_UNADJST='7' THEN 'WEEK'
                    ELSE sub_freq_unadjst.FLOAT_PMT_FREQ_LEG1_UNADJST
                END AS FLOAT_PMT_FREQ_LEG1,
                CASE
                    WHEN sub_freq_unadjst.FLOAT_PMT_FREQ_LEG1_UNADJST='MNTH' AND sub_freq_unadjst.FLOAT_PMT_FREQ_MULTI_LEG1_UNADJST='12' THEN '1'
                    WHEN sub_freq_unadjst.FLOAT_PMT_FREQ_LEG1_UNADJST='DAIL' AND sub_freq_unadjst.FLOAT_PMT_FREQ_MULTI_LEG1_UNADJST='7' THEN '1'
                    ELSE sub_freq_unadjst.FLOAT_PMT_FREQ_MULTI_LEG1_UNADJST
                END AS FLOAT_PMT_FREQ_MULTI_LEG1,

                CASE
                    WHEN sub_freq_unadjst.FLOAT_PMT_FREQ_LEG2_UNADJST='MNTH' AND sub_freq_unadjst.FLOAT_PMT_FREQ_MULTI_LEG2_UNADJST='12' THEN 'YEAR'
                    WHEN sub_freq_unadjst.FLOAT_PMT_FREQ_LEG2_UNADJST='DAIL' AND sub_freq_unadjst.FLOAT_PMT_FREQ_MULTI_LEG2_UNADJST='7' THEN 'WEEK'
                    ELSE sub_freq_unadjst.FLOAT_PMT_FREQ_LEG2_UNADJST
                END AS FLOAT_PMT_FREQ_LEG2,
                CASE
                    WHEN sub_freq_unadjst.FLOAT_PMT_FREQ_LEG2_UNADJST='MNTH' AND sub_freq_unadjst.FLOAT_PMT_FREQ_MULTI_LEG2_UNADJST='12' THEN '1'
                    WHEN sub_freq_unadjst.FLOAT_PMT_FREQ_LEG2_UNADJST='DAIL' AND sub_freq_unadjst.FLOAT_PMT_FREQ_MULTI_LEG2_UNADJST='7' THEN '1'
                    ELSE sub_freq_unadjst.FLOAT_PMT_FREQ_MULTI_LEG2_UNADJST
                END AS FLOAT_PMT_FREQ_MULTI_LEG2,

                CASE
                    WHEN sub_freq_unadjst.FLOAT_RESET_FREQUENCY_LEG1_UNADJST='MNTH' AND sub_freq_unadjst.FLOAT_RESET_FREQ_MULTI_LEG1_UNADJST='12' THEN 'YEAR'
                    WHEN sub_freq_unadjst.FLOAT_RESET_FREQUENCY_LEG1_UNADJST='DAYS' AND sub_freq_unadjst.FLOAT_RESET_FREQ_MULTI_LEG1_UNADJST='7' THEN 'WEEK'
                    ELSE sub_freq_unadjst.FLOAT_RESET_FREQUENCY_LEG1_UNADJST
                END AS FLOAT_RESET_FREQUENCY_LEG1,
                CASE
                    WHEN sub_freq_unadjst.FLOAT_RESET_FREQUENCY_LEG1_UNADJST='MNTH' AND sub_freq_unadjst.FLOAT_RESET_FREQ_MULTI_LEG1_UNADJST='12' THEN '1'
                    WHEN sub_freq_unadjst.FLOAT_RESET_FREQUENCY_LEG1_UNADJST='DAYS' AND sub_freq_unadjst.FLOAT_RESET_FREQ_MULTI_LEG1_UNADJST='7' THEN '1'
                    ELSE sub_freq_unadjst.FLOAT_RESET_FREQ_MULTI_LEG1_UNADJST
                END AS FLOAT_RESET_FREQ_MULTI_LEG1,

                CASE
                    WHEN sub_freq_unadjst.FLOAT_RESET_FREQUENCY_LEG2_UNADJST='MNTH' AND sub_freq_unadjst.FLOAT_RESET_FREQ_MULTI_LEG2_UNADJST='12' THEN 'YEAR'
                    WHEN sub_freq_unadjst.FLOAT_RESET_FREQUENCY_LEG2_UNADJST='DAYS' AND sub_freq_unadjst.FLOAT_RESET_FREQ_MULTI_LEG2_UNADJST='7' THEN 'WEEK'
                    ELSE sub_freq_unadjst.FLOAT_RESET_FREQUENCY_LEG2_UNADJST
                END AS FLOAT_RESET_FREQUENCY_LEG2,
                CASE
                    WHEN sub_freq_unadjst.FLOAT_RESET_FREQUENCY_LEG2_UNADJST='MNTH' AND sub_freq_unadjst.FLOAT_RESET_FREQ_MULTI_LEG2_UNADJST='12' THEN '1'
                    WHEN sub_freq_unadjst.FLOAT_RESET_FREQUENCY_LEG2_UNADJST='DAYS' AND sub_freq_unadjst.FLOAT_RESET_FREQ_MULTI_LEG2_UNADJST='7' THEN '1'
                    ELSE sub_freq_unadjst.FLOAT_RESET_FREQ_MULTI_LEG2_UNADJST
                END AS FLOAT_RESET_FREQ_MULTI_LEG2,

                CASE
                    WHEN sub_freq_unadjst.UPI_UNDRLNG_INSTR_TERM_UNT_UNADJST='MNTH' AND sub_freq_unadjst.UPI_UNDRLNG_INSTR_TERM_VAL_UNADJST='12' THEN 'YEAR'
                    WHEN sub_freq_unadjst.UPI_UNDRLNG_INSTR_TERM_UNT_UNADJST='DAYS' AND sub_freq_unadjst.UPI_UNDRLNG_INSTR_TERM_VAL_UNADJST='7' THEN 'WEEK'
                    ELSE sub_freq_unadjst.UPI_UNDRLNG_INSTR_TERM_UNT_UNADJST
                END AS UPI_UNDRLNG_INSTR_TERM_UNT,
                CASE
                    WHEN sub_freq_unadjst.UPI_UNDRLNG_INSTR_TERM_UNT_UNADJST='MNTH' AND sub_freq_unadjst.UPI_UNDRLNG_INSTR_TERM_VAL_UNADJST='12' THEN '1'
                    WHEN sub_freq_unadjst.UPI_UNDRLNG_INSTR_TERM_UNT_UNADJST='DAYS' AND sub_freq_unadjst.UPI_UNDRLNG_INSTR_TERM_VAL_UNADJST='7' THEN '1'
                    ELSE sub_freq_unadjst.UPI_UNDRLNG_INSTR_TERM_VAL_UNADJST
                END AS UPI_UNDRLNG_INSTR_TERM_VAL,

                CASE
                    WHEN sub_freq_unadjst.UPI_OTHR_LEG_REF_RATE_TRM_UNT_UNADJST='MNTH' AND sub_freq_unadjst.UPI_OTHR_LEG_REF_RATE_TRM_VAL_UNADJST='12' THEN 'YEAR'
                    WHEN sub_freq_unadjst.UPI_OTHR_LEG_REF_RATE_TRM_UNT_UNADJST='DAYS' AND sub_freq_unadjst.UPI_OTHR_LEG_REF_RATE_TRM_VAL_UNADJST='7' THEN 'WEEK'
                    ELSE sub_freq_unadjst.UPI_OTHR_LEG_REF_RATE_TRM_UNT_UNADJST
                END AS UPI_OTHR_LEG_REF_RATE_TRM_UNT,
                CASE
                    WHEN sub_freq_unadjst.UPI_OTHR_LEG_REF_RATE_TRM_UNT_UNADJST='MNTH' AND sub_freq_unadjst.UPI_OTHR_LEG_REF_RATE_TRM_VAL_UNADJST='12' THEN '1'
                    WHEN sub_freq_unadjst.UPI_OTHR_LEG_REF_RATE_TRM_UNT_UNADJST='DAYS' AND sub_freq_unadjst.UPI_OTHR_LEG_REF_RATE_TRM_VAL_UNADJST='7' THEN '1'
                    ELSE sub_freq_unadjst.UPI_OTHR_LEG_REF_RATE_TRM_VAL_UNADJST
                END AS UPI_OTHR_LEG_REF_RATE_TRM_VAL,
                CASE
                    WHEN sub_freq_unadjst.UPI_REF_RATE_TRM_UNT_UNADJST='MNTH' AND sub_freq_unadjst.UPI_REF_RATE_TRM_VAL_UNADJST='12' THEN 'YEAR'
                    WHEN sub_freq_unadjst.UPI_REF_RATE_TRM_UNT_UNADJST='DAYS' AND sub_freq_unadjst.UPI_REF_RATE_TRM_VAL_UNADJST='7' THEN 'WEEK'
                    ELSE sub_freq_unadjst.UPI_REF_RATE_TRM_UNT_UNADJST
                END AS UPI_REF_RATE_TRM_UNT,
                CASE
                    WHEN sub_freq_unadjst.UPI_REF_RATE_TRM_UNT_UNADJST='MNTH' AND sub_freq_unadjst.UPI_REF_RATE_TRM_VAL_UNADJST='12' THEN '1'
                    WHEN sub_freq_unadjst.UPI_REF_RATE_TRM_UNT_UNADJST='DAYS' AND sub_freq_unadjst.UPI_REF_RATE_TRM_VAL_UNADJST='7' THEN '1'
                    ELSE sub_freq_unadjst.UPI_REF_RATE_TRM_VAL_UNADJST
                END AS UPI_REF_RATE_TRM_VAL
            FROM DUAL
        ) sub_freq_adjusted
        CROSS APPLY
        (
            SELECT
                DECODE(DMX.THD_NOTIONAL_SCHEDULE_CODE,'C','Constant','I','Accreting','D','Amortizing','Y','Custom',NULL) AS NOTIONAL_SCHEDULE
            FROM DUAL
        ) sub_notional_schedule
        CROSS APPLY
        (
            SELECT
                CASE
                    WHEN THD_TRD_CLASS_SRC_NAME = 'IRD_CF' THEN 'European'
                    ELSE DECODE(DMX.TRO_AMEREURO_CODE,'A','American','B','Bermudan','E','European',NULL)
                END AS EXERCISE
            FROM DUAL
        ) sub_exercise
        CROSS APPLY
        (
            SELECT
                CASE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_CF','IRD_OSWP','IRD_OPT_OTC') THEN
                        CASE
                            WHEN DMX.THD_SETTL_MOD_CODE = 0 THEN
								CASE
									WHEN NVL(DMX.THD_INITIALPAYMENT_AMT, 0) != 0 THEN ABS(DMX.THD_INITIALPAYMENT_AMT)
									ELSE 0
								END
                            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CF' THEN ABS(DECODE(DMX.SUM_FFL_PREMIUM_AMT_NEAR_PRE_FLW,0,0,DMX.SUM_FFL_PREMIUM_AMT_NEAR_PRE_FLW))
							WHEN NVL(DMX.SUM_FFL_PREMIUM_AMT_NEAR, 0) != 0 THEN ABS(DMX.SUM_FFL_PREMIUM_AMT_NEAR)
							ELSE 0
                        END
                    ELSE NULL
                 END AS UPFRONT_FEE_AMOUNT
            FROM DUAL
        ) sub_upfront_fee_amount
        CROSS APPLY
        (
            --<GH_Rewrite_Work>
            --champs splitt s CFTC/CSA
            SELECT
                CASE
                    WHEN DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE  'IR Infl Swap%' AND DMX.TRP_CREDIT_LINKED_NEAR = 'Y' AND DMX.THD_FIX_FLOAT_RATE_IND = 'F' THEN NULL
                    WHEN DMX.THD_POST_PRICED_SWAP_IND_FLG = 'Y' THEN NULL
                    ELSE FIXED_RATE1_TMP
                END AS FIXED_RATE1_CFTC,
                CASE
                    WHEN DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE  'IR Infl Swap%' AND DMX.TRP_CREDIT_LINKED_NEAR = 'Y' AND DMX.THD_FIX_FLOAT_RATE_IND = 'F' THEN NULL
                    WHEN DMX.THD_POST_PRICED_SWAP_IND_FLG = 'Y' THEN 9.9999999999
                    ELSE FIXED_RATE1_TMP
                END AS FIXED_RATE1_CSA,
                CASE
                    WHEN DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE  'IR Infl Swap%' AND DMX.TRP_CREDIT_LINKED_NEAR = 'Y' AND DMX.THD_FIX_FLOAT_RATE_IND = 'F' THEN NULL
                    WHEN DMX.THD_POST_PRICED_SWAP_IND_FLG = 'Y' THEN NULL
                    ELSE FIXED_RATE2_TMP
                END AS FIXED_RATE2_CFTC,
                CASE
                    WHEN DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE  'IR Infl Swap%' AND DMX.TRP_CREDIT_LINKED_NEAR = 'Y' AND DMX.THD_FIX_FLOAT_RATE_IND = 'F' THEN NULL
                    WHEN DMX.THD_POST_PRICED_SWAP_IND_FLG = 'Y' THEN 9.9999999999
                    ELSE FIXED_RATE2_TMP
                END AS FIXED_RATE2_CSA
            FROM
            (
                SELECT
                    CASE
                        WHEN NVL(DMX.THD_POST_PRICED_SWAP_IND_FLG,' ') != 'Y' THEN
                            CASE
                                WHEN DMX.THD_TRD_CLASS_SRC_NAME='IRD_BOND_FWD' THEN DMX.THD_PRICE_AMT*100 -- The value is divided by 100 on DWH side
                                WHEN DMX.THD_TRD_CLASS_SRC_NAME='IRD_FRA' /*and leg2 is fixed, but FRAs have only 1 leg*/  THEN DMX.THD_PRICE_AMT -- The value is divided by 100 on DWH side
                                WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS','IRD_TRS') AND DMX.TRP_FIX_FLOAT_RATE_IND_NEAR='F' THEN DMX.MAX_FIX_MARGIN_RATE_NEAR_INT_IN_PERIOD/100
                                ELSE NULL
                            END
                        ELSE NULL
                    END AS FIXED_RATE1_TMP,
                    CASE
                        WHEN NVL(DMX.THD_POST_PRICED_SWAP_IND_FLG,' ') != 'Y' AND DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS','IRD_TRS') AND DMX.TRP_FIX_FLOAT_RATE_IND_FAR='F' THEN DMX.MAX_FIX_MARGIN_RATE_FAR_INT_IN_PERIOD/100
                        ELSE NULL
                    END AS FIXED_RATE2_TMP
                FROM DUAL
            ) foo
            --</GH_Rewrite_Work>
        ) sub_fixed_rate
        CROSS APPLY
        (
            --<GH_Rewrite_Work>
            -- ark...
            SELECT
                DECODE(sub_fixed_rate.FIXED_RATE1_CFTC,NULL,SPREAD1_CFTC_TMP,NULLIF(SPREAD1_CFTC_TMP,0)) AS SPREAD1_CFTC,
                DECODE(sub_fixed_rate.FIXED_RATE1_CSA,NULL,SPREAD1_CSA_TMP,NULLIF(SPREAD1_CSA_TMP,0)) AS SPREAD1_CSA,
                DECODE(sub_fixed_rate.FIXED_RATE2_CFTC,NULL,SPREAD2_CFTC_TMP,NULLIF(SPREAD2_CFTC_TMP,0)) AS SPREAD2_CFTC,
                DECODE(sub_fixed_rate.FIXED_RATE2_CSA,NULL,SPREAD2_CSA_TMP,NULLIF(SPREAD2_CSA_TMP,0)) AS SPREAD2_CSA
            FROM
            (
                SELECT
                    CASE
                        WHEN DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE  'IR Infl Swap%' AND DMX.TRP_CREDIT_LINKED_NEAR = 'Y' AND DMX.THD_FIX_FLOAT_RATE_IND = 'F' THEN sub_fixed_rate.FIXED_RATE1_CFTC
                        ELSE SPREAD1_TMP
                    END AS SPREAD1_CFTC_TMP,
                    CASE
                        WHEN DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE  'IR Infl Swap%' AND DMX.TRP_CREDIT_LINKED_NEAR = 'Y' AND DMX.THD_FIX_FLOAT_RATE_IND = 'F' THEN sub_fixed_rate.FIXED_RATE1_CSA
                        ELSE SPREAD1_TMP
                    END AS SPREAD1_CSA_TMP,
                    CASE
                        WHEN DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE  'IR Infl Swap%' AND DMX.TRP_CREDIT_LINKED_NEAR = 'Y' AND DMX.THD_FIX_FLOAT_RATE_IND = 'F' THEN sub_fixed_rate.FIXED_RATE2_CFTC
                        ELSE SPREAD2_TMP
                    END AS SPREAD2_CFTC_TMP,
                    CASE
                        WHEN DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE  'IR Infl Swap%' AND DMX.TRP_CREDIT_LINKED_NEAR = 'Y' AND DMX.THD_FIX_FLOAT_RATE_IND = 'F' THEN sub_fixed_rate.FIXED_RATE2_CSA
                        ELSE SPREAD2_TMP
                    END AS SPREAD2_CSA_TMP
                FROM
                (
                    SELECT
    --                    CASE
    --                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CF' THEN
    --                            CASE
    --                                WHEN DMX.THD_FIX_FLOAT_RATE_IND = 'V' THEN DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_MRGN_SPREAD_SIDE1,NVL(DMX.THD_CONTR_MARGIN_RATE,0) + NVL(DMX.MAX_FFL_INDEX_SPREAD_AMT_NEAR,0)) / 100
    --                                ELSE 0
    --                            END
    --                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS','IRD_FRA','IRD_TRS') THEN
    --                            CASE
    --                                WHEN DMX.THD_FIX_FLOAT_RATE_IND = 'V' THEN DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_MRGN_SPREAD_SIDE1,NVL(DMX.TRP_LEG_MARGIN_PX_RATE_VAL_NEAR,0) + NVL(DMX.MAX_FFL_INDEX_SPREAD_AMT_NEAR,0)) / 100
    --                                ELSE 0
    --                            END
    --                        ELSE NULL
    --                    END AS SPREAD1_TMP
    --                    ,CASE
    --                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS','IRD_FRA','IRD_TRS') THEN -- 2023-07-26 : IRD_CF removed from that list (leg2 needs to be NULL for this product)
    --                            CASE
    --                                WHEN DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'V' THEN DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_MRGN_SPREAD_SIDE2,NVL(DMX.TRP_LEG_MARGIN_PX_RATE_VAL_FAR,0) + NVL(DMX.MAX_FFL_INDEX_SPREAD_AMT_FAR,0)) / 100
    --                                ELSE 0
    --                            END
    --                        ELSE NULL
    --                     END AS SPREAD2_TMP
                        CASE
                            WHEN DMX.THD_POST_PRICED_SWAP_IND_FLG = 'Y' AND DMX.THD_TYPOLOGY_DESC = 'RATE LOCK-IN SWAP' AND DMX.THD_FGT_GRP IN('CS','IRS') THEN NULL
                            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CF' THEN
                                CASE
                                    WHEN DMX.THD_FIX_FLOAT_RATE_IND = 'V' THEN DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_MRGN_SPREAD_SIDE1,NVL(DMX.THD_CONTR_MARGIN_RATE,0) + NVL(DMX.MAX_FFL_INDEX_SPREAD_AMT_NEAR,0)) / 100
                                    ELSE 0
                                END
                            WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS','IRD_FRA','IRD_TRS') THEN
                                CASE
                                    WHEN DMX.THD_FIX_FLOAT_RATE_IND = 'V' THEN DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_MRGN_SPREAD_SIDE1,NVL(DMX.TRP_LEG_MARGIN_PX_RATE_VAL_NEAR,0) + NVL(DMX.MAX_FFL_INDEX_SPREAD_AMT_NEAR,0)) / 100
                                    ELSE 0
                                END
                            ELSE NULL
                        END AS SPREAD1_TMP
                        ,CASE
                            WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS','IRD_FRA','IRD_TRS') THEN -- 2023-07-26 : IRD_CF removed from that list (leg2 needs to be NULL for this product)
                                CASE
                                    WHEN DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'V' THEN DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_MRGN_SPREAD_SIDE2,NVL(DMX.TRP_LEG_MARGIN_PX_RATE_VAL_FAR,0) + NVL(DMX.MAX_FFL_INDEX_SPREAD_AMT_FAR,0)) / 100
                                    ELSE 0
                                END
                            ELSE NULL
                         END AS SPREAD2_TMP
                    FROM DUAL
                ) foo
            ) bruh
            --</GH_Rewrite_Work>
        ) sub_spread
        CROSS APPLY
        (
            SELECT
                CASE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_BOND_FWD' THEN DECODE(DMX.THD_MIFID_56_CODE,'CASH','Cash','PHYS','Physical','OPTL','CashOrPhysical',DMX.THD_MIFID_56_CODE)
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_OSWP' THEN DECODE(DMX.THD_DLV_MODE_VAL,'C','Cash','D','Physical','Z','Cash',DMX.THD_DLV_MODE_VAL)
                    ELSE 'Cash'
                END AS SETTLEMENT_TYPE
            FROM DUAL
        ) sub_settlement_type
        --<GH_Rewrite_Work>
        CROSS APPLY
        (
            SELECT
                foo.*
                ,CASE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS','IRD_FRA','IRD_OSWP','IRD_CF') THEN INDEX_CODE_NEAR
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_BOND_FWD','IRD_OPT_OTC') THEN NVL(DMX.RIN_ISIN_ID_INSTR,DMX.THD_ISIN_ID)
                    ELSE NULL
                END AS ISDA_21_NEAR
                ,CASE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS','IRD_FRA','IRD_OSWP','IRD_CF') THEN INDEX_CODE_FAR
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_BOND_FWD','IRD_OPT_OTC') THEN NVL(DMX.RIN_ISIN_ID_INSTR,DMX.THD_ISIN_ID)
                    ELSE NULL
                END AS ISDA_21_FAR
            FROM
                (
                    SELECT
                        DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_ISDA06_CODE_SIDE1,DMX.THD_ISDA2006_NEAR_LEG_REF_CODE) AS ISDA_06_NEAR
                        ,DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_ISDA06_CODE_SIDE2,DMX.THD_ISDA2006_FAR_LEG_REF_CODE) AS ISDA_06_FAR
                        ,DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_CURRNT_ISDA_CODE_SIDE1,DMX.THD_ISDA_NEAR_LEG_REF_CODE_VAL) AS INDEX_CODE_NEAR
                        ,DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_CURRNT_ISDA_CODE_SIDE2,DMX.THD_ISDA_FAR_LEG_REF_CODE_VAL) AS INDEX_CODE_FAR
                        ,CASE
                            WHEN DMX.IS_MULTIPHASE = 'Y' AND TRIM(DMX.MLT_INDEX_LABEL_SIDE1) IS NOT NULL THEN 'Y'
                            WHEN DMX.IS_MULTIPHASE = 'N' AND DMX.THD_FIX_FLOAT_RATE_IND = 'F' THEN 'Y'
                            ELSE 'N'
                         END AS IS_FIXED_NEAR
                        ,CASE
                            WHEN DMX.IS_MULTIPHASE = 'Y' AND TRIM(DMX.MLT_INDEX_LABEL_SIDE2) IS NOT NULL THEN 'Y'
                            WHEN DMX.IS_MULTIPHASE = 'N' AND DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'F' THEN 'Y'
                            ELSE 'N'
                         END AS IS_FIXED_FAR
                    FROM DUAL
                ) foo
        ) sub_isda
        --</GH_Rewrite_Work>
        CROSS APPLY
        (
            SELECT
                CASE
                    WHEN DMX.THD_ISDA_CODE_YEAR = 'isda06' THEN DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_ISDA06_CODE_SIDE1,DMX.THD_ISDA2006_NEAR_LEG_REF_CODE)
                    WHEN DMX.THD_ISDA_CODE_YEAR = 'isda21' THEN UNDERLIER_ID_LEG1_TMP
                    WHEN DMX.THD_TRD_DATE < TO_DATE('2021-10-04','YYYY-MM-DD') THEN DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_ISDA06_CODE_SIDE1,DMX.THD_ISDA2006_NEAR_LEG_REF_CODE)
                    ELSE UNDERLIER_ID_LEG1_TMP
                END AS UNDERLIER_ID_LEG1,

                CASE
                    WHEN DMX.THD_ISDA_CODE_YEAR = 'isda06' THEN DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_ISDA06_CODE_SIDE2,DMX.THD_ISDA2006_FAR_LEG_REF_CODE)
                    WHEN DMX.THD_ISDA_CODE_YEAR = 'isda21' THEN UNDERLIER_ID_LEG2_TMP
                    WHEN DMX.THD_TRD_DATE < TO_DATE('2021-10-04','YYYY-MM-DD') THEN DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_ISDA06_CODE_SIDE2,DMX.THD_ISDA2006_FAR_LEG_REF_CODE)
                    ELSE UNDERLIER_ID_LEG2_TMP
                END AS UNDERLIER_ID_LEG2
            FROM
            (
                SELECT
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS','IRD_FRA','IRD_OSWP','IRD_CF') AND DMX.THD_FIX_FLOAT_RATE_IND = 'V' THEN DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_CURRNT_ISDA_CODE_SIDE1,DMX.THD_ISDA_NEAR_LEG_REF_CODE_VAL)
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_BOND_FWD','IRD_OPT_OTC') THEN DMX.THD_ISIN_ID
                        ELSE NULL
                    END AS UNDERLIER_ID_LEG1_TMP,
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_TRS' AND DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'V' THEN
                            CASE
                                WHEN DMX.THD_SEC_GRP_VAL = 'Bond' THEN NVL(DMX.RIN_ISIN_ID_FAR, DMX.RIN_CUSIP_ID_FAR)
                                ELSE NULL
                            END
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS','IRD_FRA','IRD_OSWP') AND DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'V' THEN DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_CURRNT_ISDA_CODE_SIDE2,DMX.THD_ISDA_FAR_LEG_REF_CODE_VAL)
                        ELSE NULL
                    END AS UNDERLIER_ID_LEG2_TMP
                FROM DUAL
            ) foo
        ) sub_underlier_id
        LEFT JOIN UPX_ANNA_DSB upx_leg1 ON
        (
            sub_underlier_id.UNDERLIER_ID_LEG1 = upx_leg1.UPX_RATES_CODE
        )
        LEFT JOIN UPX_ANNA_DSB upx_leg2 ON
        (
            sub_underlier_id.UNDERLIER_ID_LEG2 = upx_leg2.UPX_RATES_CODE
        )
        CROSS APPLY
        (
            SELECT
                CASE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_TRS' AND DMX.THD_FIX_FLOAT_RATE_IND = 'V' THEN
                        CASE
                            WHEN TRIM(sub_underlier_id.UNDERLIER_ID_LEG1) IS NOT NULL THEN NVL(upx_leg1.UPX_RATES_CODE,'OTHER')
                            ELSE '~~~'
                        END
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS','IRD_FRA','IRD_OSWP') AND DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'V' THEN
                        CASE
                            WHEN TRIM(sub_underlier_id.UNDERLIER_ID_LEG2) IS NOT NULL THEN NVL(upx_leg2.UPX_RATES_CODE,'OTHER')
                            ELSE '~~~'
                        END
                    ELSE NULL
                END AS UPI_OTHR_LEG_REF_RATE,
                CASE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CF' AND DMX.TRO_PAYOUT_AMT = 0 AND NVL(DMX.THD_CONTRCT_TYPOLOGY_VAL,' ') NOT LIKE '%Dig%' THEN NULL
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS','IRD_FRA','IRD_OSWP','IRD_CF') AND DMX.THD_FIX_FLOAT_RATE_IND = 'V' THEN
                        CASE
                            WHEN TRIM(sub_underlier_id.UNDERLIER_ID_LEG1) IS NOT NULL THEN NVL(upx_leg1.UPX_RATES_CODE,'OTHER')
                            ELSE '~~~'
                        END
                    ELSE NULL
                END AS UPI_REF_RATE
            FROM DUAL
        ) sub_ref_rate
        CROSS APPLY
        (
            SELECT
                CASE
                    WHEN UPI_OTHR_LEG_NOTIONAL_CURR_TMP < UPI_NOTIONAL_CURR_TMP THEN 1
                    WHEN NVL(sub_ref_rate.UPI_OTHR_LEG_REF_RATE,'~~~') < NVL(sub_ref_rate.UPI_REF_RATE,'~~~') THEN 1
                    WHEN DECODE(sub_freq_adjusted.UPI_OTHR_LEG_REF_RATE_TRM_UNT,'YEAR',4,'MNTH',3,'WEEK',2,'DAYS',1,99999999999999999999) < DECODE(sub_freq_adjusted.UPI_REF_RATE_TRM_UNT,'YEAR',4,'MNTH',3,'WEEK',2,'DAYS',1,99999999999999999999) THEN 1
                    WHEN NVL(sub_freq_adjusted.UPI_OTHR_LEG_REF_RATE_TRM_VAL,99999999999999999999) < NVL(sub_freq_adjusted.UPI_REF_RATE_TRM_VAL,99999999999999999999) THEN 1
                    ELSE 0
                END AS UPI_NOTIONAL_CURR_FLIP_IND
                ,NULLIF
                (
                    CASE
                        WHEN UPI_OTHR_LEG_NOTIONAL_CURR_TMP < UPI_NOTIONAL_CURR_TMP THEN UPI_OTHR_LEG_NOTIONAL_CURR_TMP
                        ELSE UPI_NOTIONAL_CURR_TMP
                    END
                    ,'~~~'
                ) AS UPI_NOTIONAL_CURR
                ,NULLIF
                (
                    CASE
                        WHEN UPI_OTHR_LEG_NOTIONAL_CURR_TMP < UPI_NOTIONAL_CURR_TMP THEN UPI_NOTIONAL_CURR_TMP
                        ELSE UPI_OTHR_LEG_NOTIONAL_CURR_TMP
                    END
                    ,'~~~'
                ) AS UPI_OTHR_LEG_NOTIONAL_CURR
            FROM
            (
                SELECT
                    REPLACE
                    (
                        NVL
                        (
                            CASE
                                WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CS' THEN DMX.TRP_FX_EQUIV_CCY_CODE_NEAR
                                WHEN DMX.THD_TRD_CLASS_SRC_NAME LIKE 'IRD%' AND DMX.THD_FGT_GRP NOT IN('RTRN','CS') THEN DMX.THD_QTY_CCY_CODE
                            END
                            ,'~~~'
                        )
                        ,'CNH'
                        ,'CNY'
                    ) AS UPI_NOTIONAL_CURR_TMP
                    ,REPLACE
                    (
                        NVL
                        (
                            CASE
                                WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CS' THEN DMX.TRP_FX_EQUIV_CCY_CODE_FAR
                                WHEN DMX.THD_TRD_CLASS_SRC_NAME LIKE 'IRD%' AND DMX.THD_TRD_QUALIF_VAL IN('OSWP','SWP') AND DMX.THD_TRD_CLASS_SRC_NAME != 'IRD_RTRN_BSK' THEN DMX.TRP_SWAP_NOTIONAL_CCY_FAR
                                ELSE NULL
                            END
                            ,'~~~'
                        )
                        ,'CNH'
                        ,'CNY'
                    ) AS UPI_OTHR_LEG_NOTIONAL_CURR_TMP
                FROM DUAL
            ) foo
        ) sub_upi_notional_curr
        CROSS APPLY
        (
            SELECT
                CASE
                    WHEN sub_upi_notional_curr.UPI_NOTIONAL_CURR_FLIP_IND = 1 THEN sub_ref_rate.UPI_OTHR_LEG_REF_RATE
                    ELSE sub_ref_rate.UPI_REF_RATE
                END AS UPI_REF_RATE,
                CASE
                    WHEN sub_upi_notional_curr.UPI_NOTIONAL_CURR_FLIP_IND = 1 THEN sub_ref_rate.UPI_REF_RATE
                    ELSE sub_ref_rate.UPI_OTHR_LEG_REF_RATE
                END AS UPI_OTHR_LEG_REF_RATE,

                CASE
                    WHEN sub_upi_notional_curr.UPI_NOTIONAL_CURR_FLIP_IND = 1 THEN sub_freq_adjusted.UPI_OTHR_LEG_REF_RATE_TRM_UNT
                    ELSE sub_freq_adjusted.UPI_REF_RATE_TRM_UNT
                END AS UPI_REF_RATE_TRM_UNT,
                CASE
                    WHEN sub_upi_notional_curr.UPI_NOTIONAL_CURR_FLIP_IND = 1 THEN sub_freq_adjusted.UPI_REF_RATE_TRM_UNT
                    ELSE sub_freq_adjusted.UPI_OTHR_LEG_REF_RATE_TRM_UNT
                END AS UPI_OTHR_LEG_REF_RATE_TRM_UNT,

                CASE
                    WHEN sub_upi_notional_curr.UPI_NOTIONAL_CURR_FLIP_IND = 1 THEN sub_freq_adjusted.UPI_OTHR_LEG_REF_RATE_TRM_VAL
                    ELSE sub_freq_adjusted.UPI_REF_RATE_TRM_VAL
                END AS UPI_REF_RATE_TRM_VAL,
                CASE
                    WHEN sub_upi_notional_curr.UPI_NOTIONAL_CURR_FLIP_IND = 1 THEN sub_freq_adjusted.UPI_REF_RATE_TRM_VAL
                    ELSE sub_freq_adjusted.UPI_OTHR_LEG_REF_RATE_TRM_VAL
                END AS UPI_OTHR_LEG_REF_RATE_TRM_VAL
            FROM DUAL
        ) sub_flipped_cols_except_currency
        CROSS APPLY
        (
            SELECT
                CASE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_BOND_FWD' THEN DECODE(DMX.THD_MIFID_56_CODE,'OPTL','CASH',DMX.THD_MIFID_56_CODE)
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_OSWP' THEN DECODE(DMX.THD_DLV_MODE_VAL,'D','PHYS','CASH')
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_OPT_OTC' THEN DMX.THD_MIFID_56_CODE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CS' AND (NVL(PNL_RAW_NEAR_LEG_ISO_CCY_CODE,' ') != TRP_COM_CCY_CODE_NEAR OR NVL(PNL_RAW_FAR_LEG_ISO_CCY_CODE,' ') != TRP_COM_CCY_CODE_FAR) THEN 'CASH'
                    ELSE 'PHYS'
                END AS UPI_DELIVERY_TYPE
            FROM DUAL
        ) sub_upi_delivery_type
        CROSS APPLY
        (
            SELECT
                CASE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_OSWP','IRD_OPT_ORG') THEN DECODE(DMX.TRO_AMEREURO_CODE,'A','American','B','Bermudan','E','European',NULL)
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CF' THEN 'European'
                    ELSE NULL
                END AS UPI_OPTION_EXERCISE_STYLE,
                CASE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_OSWP' THEN
                        CASE
                            WHEN DMX.THD_CONTRCT_TYPOLOGY_VAL = 'IR Swaption Straddle' OR DMX.TRO_PUT_CALL_IND = 'S' THEN 'OPTL'
                            WHEN DMX.TRO_PUT_CALL_IND IN('C','P') AND DMX.TRP_FIX_FLOAT_RATE_IND_NEAR = 'F' THEN DECODE(DMX.TRP_PAY_RECV_IND_NEAR,'P','PUTO','R','CALL',NULL)
                            ELSE 'OPTL'
                        END
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CF' THEN DECODE(DMX.TRO_PAYOUT_RATE_TYPE,'Cap','CALL','Floor','PUTO','OPTL')
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_OPT_OTC' THEN DECODE(DMX.TRO_PUT_CALL_IND,'C','CALL','P','PUTO','OPTL')
                ELSE NULL
                END AS UPI_OPTION_TYPE
            FROM DUAL
        ) sub_upi_option_type
        CROSS APPLY
        (
            SELECT
                CASE
                    WHEN DMX.TRP_FIX_FLOAT_RATE_IND_NEAR = DMX.TRP_FIX_FLOAT_RATE_IND_FAR THEN
                        CASE
                            WHEN DMX.TRP_FIX_FLOAT_RATE_IND_NEAR = 'F' THEN 'Fixed_Fixed'
                            WHEN UPPER(DMX.THD_IDX_CLASS_SIDE1) LIKE '%OIS%' OR UPPER(DMX.THD_IDX_CLASS_SIDE2) LIKE '%OIS%' THEN 'Basis_OIS'
                            ELSE 'Basis'
                        END
                    ELSE
                        CASE
                            WHEN DMX.THD_ZERO_COUPON_IND = 'Y' THEN 'Fixed_Float_Zero_Coupon'
                            WHEN UPPER(DMX.THD_IDX_CLASS_SIDE1) LIKE '%OIS%' OR UPPER(DMX.THD_IDX_CLASS_SIDE2) LIKE '%OIS%' THEN 'Fixed_Float_OIS'
                            ELSE 'Fixed_Float'
                        END
                END AS UPI_PRODUCT
            FROM DUAL
        ) sub_upi_product_IRS_rule
		LEFT JOIN BASIS_CONV_MAP BCM_NEAR ON
		(
            CASE
                WHEN DMX.IS_MULTIPHASE = 'Y' THEN DMX.MLT_DAY_COUNT_CONV_DESC_SIDE1
                ELSE COALESCE(DMX.TRP_BASIS_CONV_NEAR,DMX.TRO_BASIS_CONV,DMX.TRS_BASIS_CONV)
            END = BCM_NEAR.INVAL
        )
        LEFT JOIN BASIS_CONV_MAP BCM_FAR ON
		(
            CASE
                WHEN DMX.IS_MULTIPHASE = 'Y' THEN DMX.MLT_DAY_COUNT_CONV_DESC_SIDE2
                ELSE DMX.TRP_BASIS_CONV_FAR
            END = BCM_FAR.INVAL
        )
        CROSS APPLY
        (
            SELECT
                TRIM(',' FROM (
                    CASE
                        WHEN DMX.THD_FGT_GRP NOT IN ('OSWP','CF','BOND','OPT','RTRN') THEN DECODE(DMX.THD_INITIALPAYMENT_AMT,0,NULL,'UFRO')
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN ('IRD_IRS','IRD_CS','IRD_FRA','IRD_TRS') AND DMX.LIST_UFRO_RPL_P_C IS NOT NULL THEN ',' || DMX.LIST_UFRO_RPL_P_C
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CS' AND DMX.LIST_PEXH_PRI IS NOT NULL THEN ',' || DMX.LIST_PEXH_PRI
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_FGT_GRP != 'RTRN' /*AND THD_TRD_CLASS_SRC_NAME != 'IRD_BOND_FWD'*/ AND DMX.LIST_UWIN_MOP IS NOT NULL THEN ',' || DMX.LIST_UWIN_MOP
                        ELSE NULL
                    END
--                    ||
--                    CASE
--                        WHEN THD_TRD_CLASS_SRC_NAME = 'IRD_BOND_FWD' AND LIST_UWIN_XIT IS NOT NULL THEN ',' || DMX.LIST_UWIN_XIT -- d j  les XIT avec la date...
--                    END
                    )) AS OTH_PAYMENT_TYPE,

                TRIM(',' FROM (
                    CASE
                        WHEN DMX.THD_FGT_GRP NOT IN ('OSWP','CF','BOND','OPT','RTRN') THEN DECODE(DMX.THD_INITIALPAYMENT_AMT,0,NULL,RTRIM(TO_CHAR(FMT_ELT.FLEXIBLE_ROUND(ABS(DMX.THD_INITIALPAYMENT_AMT),2,'HALF_DOWN'),'FM999999999999999999999999999999990.99'),'.'))      --DECODE(DMX.THD_INITIALPAYMENT_AMT,0,NULL,',' || RTRIM(TO_CHAR(ABS(DMX.THD_INITIALPAYMENT_AMT), 'FM99999999999990.999999999999'), '.'))
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN ('IRD_IRS','IRD_CS','IRD_FRA','IRD_TRS') AND DMX.LIST_FFL_PYMT_AMT_RPL_P_C IS NOT NULL THEN ',' || DMX.LIST_FFL_PYMT_AMT_RPL_P_C
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CS' AND DMX.LIST_FFL_CAPTL_EXCH_AMT_PRI IS NOT NULL THEN ',' || DMX.LIST_FFL_CAPTL_EXCH_AMT_PRI
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN  DMX.THD_FGT_GRP != 'RTRN' /*AND THD_TRD_CLASS_SRC_NAME != 'IRD_BOND_FWD'*/ AND DMX.LIST_FFL_PYMT_AMT_MOP IS NOT NULL  THEN ',' || DMX.LIST_FFL_PYMT_AMT_MOP
                        ELSE NULL
                    END
--                    ||
--                    CASE
--                        WHEN THD_TRD_CLASS_SRC_NAME = 'IRD_BOND_FWD' AND LIST_PAY_AMT_XIT IS NOT NULL THEN ',' || DMX.LIST_PAY_AMT_XIT -- d j  les XIT avec la date...
--                    END
                )) AS OTH_PAYMENT_AMOUNT,

                TRIM(',' FROM (
                    CASE
                        WHEN DMX.THD_FGT_GRP NOT IN ('OSWP','CF','BOND','OPT','RTRN') THEN DECODE(DMX.THD_INITIALPAYMENT_AMT,0,NULL,DECODE(DMX.THD_PREMIUMCCY,'CNH','CNY',DMX.THD_PREMIUMCCY))
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN ('IRD_IRS','IRD_CS','IRD_FRA','IRD_TRS') AND DMX.LIST_FFL_PMT_CCY_CODE_RPL_P_C IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_CCY_CODE_RPL_P_C
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CS' AND DMX.LIST_FFL_FLOW_CCY_CODE_PRI IS NOT NULL THEN ',' || DMX.LIST_FFL_FLOW_CCY_CODE_PRI
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN  DMX.THD_FGT_GRP != 'RTRN' /*AND THD_TRD_CLASS_SRC_NAME != 'IRD_BOND_FWD'*/  AND DMX.LIST_FFL_PMT_CCY_CODE_MOP IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_CCY_CODE_MOP
                        ELSE NULL
                    END
--                    ||
--                    CASE
--                        WHEN THD_TRD_CLASS_SRC_NAME = 'IRD_BOND_FWD' AND DMX.LIST_CCY_XIT IS NOT NULL THEN ',' || DMX.LIST_CCY_XIT -- d j  les XIT avec la date...
--                    END
                )) AS OTH_PAYMENT_CURR,

                TRIM(',' FROM (
                    CASE
                        WHEN DMX.THD_FGT_GRP NOT IN ('OSWP','CF','BOND','OPT','RTRN') THEN DECODE(DMX.THD_INITIALPAYMENT_AMT,0,NULL,TO_CHAR(DMX.THD_PREMIUM_PAY_DATE,'YYYY-MM-DD'))
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN ('IRD_IRS','IRD_CS','IRD_FRA','IRD_TRS') AND DMX.LIST_FFL_PMT_DATE_RPL_P_C IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_DATE_RPL_P_C
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CS' AND DMX.LIST_FFL_FLOW_PYMT_DATE_PRI IS NOT NULL THEN ',' || DMX.LIST_FFL_FLOW_PYMT_DATE_PRI
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN  DMX.THD_FGT_GRP != 'RTRN' /*AND THD_TRD_CLASS_SRC_NAME != 'IRD_BOND_FWD'*/  AND DMX.LIST_FFL_PMT_DATE_MOP IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_DATE_MOP
                        ELSE NULL
                    END
--                    ||
--                    CASE
--                        WHEN THD_TRD_CLASS_SRC_NAME = 'IRD_BOND_FWD' AND DMX.LIST_PAY_DATE_XIT IS NOT NULL THEN ',' || DMX.LIST_PAY_DATE_XIT -- d j  les XIT avec la date...
--                    END
                )) AS OTH_PAYMENT_DATE,

                TRIM(',' FROM (
                    CASE
                        WHEN DMX.THD_FGT_GRP NOT IN ('OSWP','CF','BOND','OPT','RTRN') AND NVL(DMX.THD_INITIALPAYMENT_AMT, 0) != 0 THEN
                            CASE
                                WHEN DMX.THD_INITIALPAYMENT_AMT < 0 THEN DMX.REPORTING_PARTY_LEI
                                ELSE DMX.COUNTERPARTY_LEI
                            END
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN ('IRD_IRS','IRD_CS','IRD_FRA','IRD_TRS') AND DMX.LIST_FFL_PMT_PAY_LEI_RPL_P_C IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_PAY_LEI_RPL_P_C
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CS' AND DMX.LIST_FFL_RPY_LEI_PRI_PAY IS NOT NULL THEN ',' || DMX.LIST_FFL_RPY_LEI_PRI_PAY
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN  DMX.THD_FGT_GRP != 'RTRN' /*AND THD_TRD_CLASS_SRC_NAME != 'IRD_BOND_FWD'*/  AND DMX.LIST_FFL_PMT_PAY_LEI_MOP IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_PAY_LEI_MOP
                        ELSE NULL
                    END
--                    ||
--                    CASE
--                        WHEN THD_TRD_CLASS_SRC_NAME = 'IRD_BOND_FWD' AND DMX.LIST_PAYER_XIT IS NOT NULL THEN ',' || DMX.LIST_PAYER_XIT -- d j  les XIT avec la date...
--                    END
                )) AS OTH_PAYMENT_PAYER,

                TRIM(',' FROM (
                    CASE
                        WHEN DMX.THD_FGT_GRP NOT IN ('OSWP','CF','BOND','OPT','RTRN') AND NVL(DMX.THD_INITIALPAYMENT_AMT, 0) != 0 THEN
                            CASE
                                WHEN DMX.THD_INITIALPAYMENT_AMT > 0 THEN DMX.REPORTING_PARTY_LEI
                                ELSE DMX.COUNTERPARTY_LEI
                            END
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN ('IRD_IRS','IRD_CS','IRD_FRA','IRD_TRS') AND DMX.LIST_FFL_PMT_RECV_LEI_RPL_P_C IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_RECV_LEI_RPL_P_C
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CS' AND DMX.LIST_FFL_RPY_LEI_PRI_RECV IS NOT NULL THEN ',' || DMX.LIST_FFL_RPY_LEI_PRI_RECV
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN  DMX.THD_FGT_GRP != 'RTRN' /*AND THD_TRD_CLASS_SRC_NAME != 'IRD_BOND_FWD'*/  AND DMX.LIST_FFL_PMT_RECV_LEI_MOP IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_RECV_LEI_MOP
                        ELSE NULL
                    END
--                    ||
--                    CASE
--                        WHEN THD_TRD_CLASS_SRC_NAME = 'IRD_BOND_FWD' AND DMX.LIST_RECEIVER_XIT IS NOT NULL THEN ',' || DMX.LIST_RECEIVER_XIT -- d j  les XIT avec la date...
--                    END
                )) AS OTH_PAYMENT_RECEIVER,
                TRIM(',' FROM (
                    CASE
                        WHEN DMX.THD_FGT_GRP NOT IN ('OSWP','CF','BOND','OPT','RTRN') AND NVL(DMX.THD_INITIALPAYMENT_AMT, 0) != 0 THEN
                            CASE
                                WHEN DMX.THD_INITIALPAYMENT_AMT < 0 THEN 'LEI'
                                ELSE DMX.PARTY_TYP2
                            END
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN ('IRD_IRS','IRD_CS','IRD_FRA','IRD_TRS') AND DMX.LIST_FFL_IPAY_PAY_TYPE_P_C IS NOT NULL THEN ',' || DMX.LIST_FFL_IPAY_PAY_TYPE_P_C
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CS' AND DMX.LIST_FFL_PRI_INIT_FIN_PAY_TYPE IS NOT NULL THEN ',' || DMX.LIST_FFL_PRI_INIT_FIN_PAY_TYPE
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN  DMX.THD_FGT_GRP != 'RTRN' /*AND THD_TRD_CLASS_SRC_NAME != 'IRD_BOND_FWD'*/ AND DMX.LIST_FFL_PAY_TYPE_MOP IS NOT NULL THEN ',' || DMX.LIST_FFL_PAY_TYPE_MOP
                        ELSE NULL
                    END
--                    ||
--                    CASE
--                        WHEN THD_TRD_CLASS_SRC_NAME = 'IRD_BOND_FWD' AND DMX.LIST_PAYER_TYPE_XIT IS NOT NULL THEN ',' || DMX.LIST_PAYER_TYPE_XIT -- d j  les XIT avec la date...
--                    END
                )) AS OTH_PAYMENT_PAYER_TYPE,

                TRIM(',' FROM (
                    CASE
                        WHEN DMX.THD_FGT_GRP NOT IN ('OSWP','CF','BOND','OPT','RTRN') AND NVL(DMX.THD_INITIALPAYMENT_AMT, 0) != 0 THEN
                            CASE
                                WHEN DMX.THD_INITIALPAYMENT_AMT > 0 THEN 'LEI'
                                ELSE DMX.PARTY_TYP2
                            END
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN ('IRD_IRS','IRD_CS','IRD_FRA','IRD_TRS') AND DMX.LIST_FFL_IPAY_RECV_TYPE_P_C IS NOT NULL THEN ',' || DMX.LIST_FFL_IPAY_RECV_TYPE_P_C
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CS' AND DMX.LIST_FFL_PRI_INIT_FIN_RECV_TYPE IS NOT NULL THEN ',' || DMX.LIST_FFL_PRI_INIT_FIN_RECV_TYPE
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN  DMX.THD_FGT_GRP != 'RTRN' /*AND THD_TRD_CLASS_SRC_NAME != 'IRD_BOND_FWD'*/ AND DMX.LIST_FFL_RECV_TYPE_MOP IS NOT NULL THEN ',' || DMX.LIST_FFL_RECV_TYPE_MOP
                        ELSE NULL
                    END
--                    ||
--                    CASE
--                        WHEN THD_TRD_CLASS_SRC_NAME = 'IRD_BOND_FWD' AND DMX.LIST_RECEIVER_TYPE_XIT IS NOT NULL THEN ',' || DMX.LIST_RECEIVER_TYPE_XIT -- d j  les XIT avec la date...
--                    END
                )) AS OTH_PAYMENT_RECEIVER_TYPE
            FROM DUAL
        ) sub_oth_fields

        --<GH_Rewrite_Work>
        CROSS APPLY
        (
            SELECT
                EFFECTIVE_DATE,
                END_DATE,
                ABS(MONTHS_BETWEEN(END_DATE,EFFECTIVE_DATE)) / 12 AS END_MINUS_EFF_IN_YEARS
            FROM
            (
                SELECT
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_BOND_FWD','IRD_OPT_OTC','IRD_OSWP') THEN DMX.THD_TRD_DATE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS','IRD_FRA','IRD_CF','IRD_TRS') THEN DMX.THD_UNADJST_LEG1_START_DATE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_OPT_OTC' THEN NVL(DMX.THD_ORIG_TRADE_DATE,DMX.THD_TRD_DATE)
                        ELSE NULL
                    END EFFECTIVE_DATE,
                    CASE
                        WHEN DMX.THD_FGT_GRP NOT IN('BOND','OSWP','OPT') THEN DECODE(DMX.IS_MULTIPHASE,'Y',DMX.THD_UNDERL_SEC_MAT_DATE_SIDE1, DMX.THD_UNADJST_MAT_DATE)
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_OSWP' OR DMX.THD_FGT_GRP IN('BOND','OPT') THEN DMX.THD_PERIOD_EXPIRY_DATE
                        ELSE NULL
                    END AS END_DATE
                FROM DUAL
            ) foo
        ) sub_dates

