        CROSS APPLY
        (
            SELECT
                'Rates' AS UPI_ASSET_CLASS
                ,CASE
                    WHEN DMX.THD_FGT_GRP IN ('OPT', 'OSWP', 'CF') THEN 'Option'
                    WHEN DMX.THD_FGT_GRP IN ('IRS', 'CS') THEN 'Swap'
                    WHEN DMX.THD_FGT_GRP = 'FRA' OR DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_BOND_FWD' THEN 'Forward'
                    ELSE NULL
                 END AS UPI_INSTRUMENT_TYPE
                ,CASE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_BOND_FWD' THEN 'Debt'
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_OPT_OTC' THEN 'Debt_Option'
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_FRA' THEN 'FRA_Index'
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_OSWP' THEN 'Swaption'
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CF' AND DMX.TRO_PAYOUT_AMT = 0 THEN 'CapFloor'
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_CF','IRD_TRS') THEN 'Non_Standard'
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CS' THEN
                        CASE
                            WHEN DMX.THD_ZERO_COUPON_IND = 'Y' THEN 'Cross_Currency_Zero_Coupon'
                            WHEN DMX.TRP_FIX_FLOAT_RATE_IND_NEAR = 'F' AND DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'F' THEN 'Cross_Currency_Fixed_Fixed'
                            WHEN DMX.TRP_FIX_FLOAT_RATE_IND_NEAR = 'V' AND DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'V' THEN 'Cross_Currency_Basis'
                            WHEN COALESCE(DMX.TRP_FX_UNDERL_ISO_CCY_CODE_NEAR,DMX.TRP_FX_UNDERL_ISO_CCY_CODE_FAR,' ') NOT IN(DMX.TRP_COM_CCY_CODE_NEAR,DMX.TRP_COM_CCY_CODE_FAR) THEN 'Cross_Currency_Fixed_Float_NDS'
                            ELSE'Cross_Currency_Fixed_Float'
                        END
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_IRS' THEN sub_upi_product_IRS_rule.UPI_PRODUCT
                    ELSE NULL
                END AS UPI_PRODUCT
                ,DECODE(sub_flipped_cols_except_currency.UPI_REF_RATE,'~~~','OTHER',sub_flipped_cols_except_currency.UPI_REF_RATE) AS UPI_REF_RATE
                ,DECODE(sub_flipped_cols_except_currency.UPI_OTHR_LEG_REF_RATE,'~~~','OTHER',sub_flipped_cols_except_currency.UPI_OTHR_LEG_REF_RATE) AS UPI_OTHR_LEG_REF_RATE
                ,CASE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS','IRD_TRS') THEN sub_notional_schedule.NOTIONAL_SCHEDULE
                    ELSE NULL
                 END AS UPI_NOTIONAL_SCHEDULE
            FROM DUAL
        ) sub_upi_fields
        CROSS APPLY
        (
            SELECT
                CASE
                    --WHEN sub_upi_fields.UPI_REF_RATE = 'OTHER' THEN -- rework of the reworked rework that was reworked before it was reworked again!
                    WHEN sub_ref_rate.UPI_REF_RATE = 'OTHER' THEN -- ils veulent que la r gle utilise le UPI_REF_RATE, mais pas celui qui sort dans le rapport qui est flipp  avec une r gle b tard (ABSort dans les variables des tech specs), ils veulent la valeur AVANT le flip...
                        CASE
                            WHEN sub_isda.IS_FIXED_NEAR = 'Y' OR DMX.THD_TYPOLOGY_DESC = 'RATE LOCK-IN SWAP' THEN NULL
                            WHEN DMX.THD_ISDA_CODE_YEAR IN('isda21','isda08') OR (TRIM(DMX.THD_ISDA_CODE_YEAR) IS NULL AND DMX.THD_TRD_DATE >= TO_DATE('2021-10-04','YYYY-MM-DD')) THEN sub_isda.ISDA_21_NEAR
                            WHEN DMX.THD_ISDA_CODE_YEAR = 'isda06' OR (TRIM(DMX.THD_ISDA_CODE_YEAR) IS NULL AND DMX.THD_TRD_DATE < TO_DATE('2021-10-04','YYYY-MM-DD')) THEN DECODE(sub_isda.ISDA_06_NEAR,NULL,sub_isda.ISDA_21_NEAR,sub_isda.ISDA_06_NEAR)
                            ELSE NULL
                        END
                    --WHEN sub_upi_fields.UPI_REF_RATE = 'OTHER-INFLATION' THEN sub_isda.INDEX_CODE_NEAR  -- rework of the reworked rework that was reworked before it was reworked again!
                    WHEN sub_ref_rate.UPI_REF_RATE = 'OTHER-INFLATION' THEN sub_isda.INDEX_CODE_NEAR -- ils veulent que la r gle utilise le UPI_REF_RATE, mais pas celui qui sort dans le rapport qui est flipp  avec une r gle b tard  (ABSort dans les variables des tech specs), ils veulent la valeur AVANT le flip...
                    ELSE NULL
                END AS UNDERLIER_ID_OTHR_LEG1
                ,CASE
                    --WHEN sub_upi_fields.UPI_OTHR_LEG_REF_RATE = 'OTHER' THEN -- rework of the reworked rework that was reworked before it was reworked again!
                    WHEN sub_ref_rate.UPI_OTHR_LEG_REF_RATE = 'OTHER' THEN -- ils veulent que la r gle utilise le UPI_REF_RATE, mais pas celui qui sort dans le rapport qui est flipp  avec une r gle b tard (ABSort dans les variables des tech specs), ils veulent la valeur AVANT le flip...
                        CASE
                            WHEN sub_isda.IS_FIXED_FAR = 'Y' OR DMX.THD_TYPOLOGY_DESC = 'RATE LOCK-IN SWAP' THEN NULL
                            WHEN DMX.THD_ISDA_CODE_YEAR IN('isda21','isda08') OR (TRIM(DMX.THD_ISDA_CODE_YEAR) IS NULL AND DMX.THD_TRD_DATE >= TO_DATE('2021-10-04','YYYY-MM-DD')) THEN sub_isda.ISDA_21_FAR
                            WHEN DMX.THD_ISDA_CODE_YEAR = 'isda06' OR (TRIM(DMX.THD_ISDA_CODE_YEAR) IS NULL AND DMX.THD_TRD_DATE < TO_DATE('2021-10-04','YYYY-MM-DD')) THEN DECODE(sub_isda.ISDA_06_FAR,NULL,sub_isda.ISDA_21_FAR,sub_isda.ISDA_06_FAR)
                            ELSE NULL
                        END
                    --WHEN sub_upi_fields.UPI_OTHR_LEG_REF_RATE = 'OTHER-INFLATION' THEN sub_isda.INDEX_CODE_FAR -- rework of the reworked rework that was reworked before it was reworked again!
                    WHEN sub_ref_rate.UPI_OTHR_LEG_REF_RATE = 'OTHER-INFLATION' THEN sub_isda.INDEX_CODE_FAR -- ils veulent que la r gle utilise le UPI_REF_RATE, mais pas celui qui sort dans le rapport qui est flipp  avec une r gle b tard (ABSort dans les variables des tech specs), ils veulent la valeur AVANT le flip...
                    ELSE NULL
                END AS UNDERLIER_ID_OTHR_LEG2
            FROM DUAL
        ) sub_underlier_id_othr
        CROSS APPLY
        (
            --rework of the rework of the rework... maintenant ils veulent CFTC clearable pour CAN clearable aussi... je laisse l'ancien code l  parce que je les trust pas
