                            CASE
                                WHEN sub_upi_fields.UPI_PRODUCT = 'Fixed_Float' THEN
                                    CASE
                                        WHEN sub_upi_fields.UPI_REF_RATE LIKE '%BBSW%' AND sub_dates.END_MINUS_EFF_IN_YEARS <= 30 THEN 'Y'
                                        WHEN sub_upi_fields.UPI_REF_RATE LIKE '%CDOR%' AND sub_dates.END_MINUS_EFF_IN_YEARS <= 30 THEN 'Y'
                                        WHEN sub_upi_fields.UPI_REF_RATE LIKE 'EUR-EURIBOR%' AND sub_dates.END_MINUS_EFF_IN_YEARS <= 50 THEN 'Y'
                                        WHEN sub_upi_fields.UPI_REF_RATE LIKE 'HKD-HIBOR%' AND sub_dates.END_MINUS_EFF_IN_YEARS <= 10 THEN 'Y'
                                        WHEN sub_upi_fields.UPI_REF_RATE LIKE 'NOK-NIBOR%' AND sub_dates.END_MINUS_EFF_IN_YEARS <= 10 THEN 'Y'
                                        WHEN sub_upi_fields.UPI_REF_RATE LIKE 'PLN-WIBOR%' AND sub_dates.END_MINUS_EFF_IN_YEARS <= 10 THEN 'Y'
                                        WHEN sub_upi_fields.UPI_REF_RATE LIKE 'MXN-TIIE-BANXICO%' AND sub_dates.END_MINUS_EFF_IN_YEARS <= 21 THEN 'Y'
                                        WHEN sub_upi_fields.UPI_REF_RATE LIKE 'SEK-STIBOR%' AND sub_dates.END_MINUS_EFF_IN_YEARS <= 15 THEN 'Y'
                                        ELSE 'N'
