                                        WHEN sub_upi_fields.UPI_REF_RATE LIKE 'EUR-EURIBOR%' AND sub_dates.END_MINUS_EFF_IN_YEARS <= 50 THEN 'Y'
                                        WHEN sub_upi_fields.UPI_OTHR_LEG_REF_RATE LIKE '%BBSW%' AND sub_dates.END_MINUS_EFF_IN_YEARS <= 30 THEN 'Y'
                                        WHEN sub_upi_fields.UPI_OTHR_LEG_REF_RATE LIKE 'EUR-EURIBOR%' AND sub_dates.END_MINUS_EFF_IN_YEARS <= 50 THEN 'Y'
                                        ELSE 'N'
                                    END
