                                        WHEN sub_upi_fields.UPI_REF_RATE LIKE 'CHF-SARON%' AND sub_dates.END_MINUS_EFF_IN_YEARS <= 30 THEN 'Y'
                                        WHEN sub_upi_fields.UPI_REF_RATE LIKE 'JPY-TONA%' AND sub_dates.END_MINUS_EFF_IN_YEARS <= 30 THEN 'Y'
                                        WHEN sub_upi_fields.UPI_OTHR_LEG_REF_RATE LIKE 'AUD-AONIA-OIS%' AND sub_dates.END_MINUS_EFF_IN_YEARS <= 2 THEN 'Y'
                                        WHEN sub_upi_fields.UPI_OTHR_LEG_REF_RATE LIKE 'CAD-CORRA-OIS%' AND sub_dates.END_MINUS_EFF_IN_YEARS <= 2 THEN 'Y'
                                        WHEN sub_upi_fields.UPI_OTHR_LEG_REF_RATE LIKE 'EUR-EuroSTR%' AND sub_dates.END_MINUS_EFF_IN_YEARS <= 3 THEN 'Y'
                                        WHEN sub_upi_fields.UPI_OTHR_LEG_REF_RATE LIKE 'USD-Federal Funds%' AND sub_dates.END_MINUS_EFF_IN_YEARS <= 3 THEN 'Y'
                                        WHEN sub_upi_fields.UPI_OTHR_LEG_REF_RATE LIKE 'SGD-SORA%' AND sub_dates.END_MINUS_EFF_IN_YEARS <= 10 THEN 'Y'
