                                ELSE 'N'
                            END
                        WHEN sub_upi_fields.UPI_ASSET_CLASS = 'Rates' AND sub_upi_fields.UPI_PRODUCT LIKE 'FRA%' THEN
                            CASE
                                WHEN sub_upi_fields.UPI_REF_RATE LIKE 'EUR-EURIBOR%' AND sub_dates.END_MINUS_EFF_IN_YEARS <= 3 THEN 'Y'
                                WHEN sub_upi_fields.UPI_REF_RATE LIKE 'SEK-STIBOR%' AND sub_dates.END_MINUS_EFF_IN_YEARS <= 3 THEN 'Y'
                                WHEN sub_upi_fields.UPI_REF_RATE LIKE 'PLN-WIBOR%' AND sub_dates.END_MINUS_EFF_IN_YEARS <= 2 THEN 'Y'
                                WHEN sub_upi_fields.UPI_REF_RATE LIKE 'NOK-NIBOR%' AND sub_dates.END_MINUS_EFF_IN_YEARS <= 2 THEN 'Y'
                                ELSE 'N'
                            END
                        ELSE 'N'
                    END AS CFTC_CLEARABLE
                FROM DUAL
            ) bruh
        ) sub_clearable
        CROSS APPLY
        (
            SELECT
                CASE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CF' AND THD_POST_PRICED_SWAP_IND_FLG = 'Y' THEN 9.9999999999
                    ELSE STRIKE_PRICE_TMP
                END AS STRIKE_PRICE_CSA
                ,CASE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CF' AND THD_POST_PRICED_SWAP_IND_FLG = 'Y' THEN NULL
                    ELSE STRIKE_PRICE_TMP
                END AS STRIKE_PRICE_CFTC
                ,STRIKE_PRICE_CURR_TMP AS STRIKE_PRICE_CURR_CFTC
                ,STRIKE_PRICE_CURR_TMP AS STRIKE_PRICE_CURR_CSA
            FROM
            (
                SELECT
    --                CASE
    --                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_OSWP' THEN DMX.TRO_FLOOR_STRIKE_PX_VAL / 100
    --                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_OPT_OTC' THEN DMX.TRO_FLOOR_STRIKE_PX_VAL
    --                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CF' THEN
    --                        CASE
    --                            WHEN DMX.TRO_PUT_CALL_IND IN('R','G') THEN DMX.TRO_CAP_STRIKE_PX_VAL / 100
    --                            ELSE DMX.TRO_FLOOR_STRIKE_PX_VAL / 100
    --                        END
    --                    ELSE NULL
    --                END AS STRIKE_PRICE
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_OSWP' THEN DMX.TRO_FLOOR_STRIKE_PX_VAL / 100
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_OPT_OTC' THEN DMX.TRO_FLOOR_STRIKE_PX_VAL
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CF' THEN
                            CASE
                                WHEN NVL(DMX.THD_PRICE_SCHEDULE_CODE,' ') != 'Y' THEN
                                    CASE
                                        WHEN DMX.TRO_PUT_CALL_IND IN('R','G') THEN DMX.TRO_CAP_STRIKE_PX_VAL / 100
                                        ELSE DMX.TRO_FLOOR_STRIKE_PX_VAL / 100
                                    END
                                ELSE DMX.MAX_FFL_PERIOD_STRIKE_FIELD_NEAR_INT_CPN_IN_PERIOD / 100
                            END
                        ELSE NULL
                    END AS STRIKE_PRICE_TMP,
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_OPT_OTC' THEN DMX.THD_NOMINAL_CCY_CODE
                        ELSE NULL
                    END AS STRIKE_PRICE_CURR_TMP
                FROM DUAL
            ) foo
        ) sub_strike
        --</GH_Rewrite_Work>
)
