    ,trd.EFFECTI_DATE_PRICE
    ,trd.END_NOTIONAL_PRICE
    ,trd.PRICE_SCHEDULE
    ,trd.UNDERLYING_ASSET_PLTF_LEG1
    ,trd.UNDERLYING_ASSET_PLTF_LEG2

