FROM FINAL_DATA trd
LEFT JOIN UPI_ANNA_DSB upi_bundle_fixed_float ON
(
    -- Cette jointure est valide pour les templates suivants :
    --UPI-6	    RATES/SWAP/FIXED_FLOAT
    --UPI-67	RATES/SWAP/FIXED_FLOAT_ZERO_COUPON
    --UPI-68	RATES/SWAP/FIXED_FLOAT_OIS
    upi_bundle_fixed_float.UPI_INT_CODE IN
    (
        'Swap:Fixed_Float'
        ,'Swap:Fixed_Float_Zero_Coupon'
        ,'Swap:Fixed_Float_OIS'
    )
    AND NVL(trd.UPI_INSTRUMENT_TYPE || ':' || trd.UPI_PRODUCT,' ') = upi_bundle_fixed_float.UPI_INT_CODE
    AND NVL(trd.UPI_ASSET_CLASS,' ') = upi_bundle_fixed_float.UPI_INT_IDX
    AND NVL(trd.UPI_NOTIONAL_CURR,' ') = upi_bundle_fixed_float.UPI_NOTIONAL_LEG1_CCY
    AND COALESCE(trd.UPI_REF_RATE,trd.UPI_OTHR_LEG_REF_RATE,' ') = upi_bundle_fixed_float.UPI_REFERENCE_RATE_LEG1
    AND COALESCE(trd.UPI_REF_RATE_TRM_VAL,trd.UPI_OTHR_LEG_REF_RATE_TRM_VAL,' ') = upi_bundle_fixed_float.UPI_UNDERLYING_INDEX_TERM_VAL
    AND COALESCE(trd.UPI_REF_RATE_TRM_UNT,trd.UPI_OTHR_LEG_REF_RATE_TRM_UNT,' ') = upi_bundle_fixed_float.UPI_UNDERLYING_INDEX_TERM_UNT
    AND NVL(trd.UPI_NOTIONAL_SCHEDULE,' ') = upi_bundle_fixed_float.UPI_TRANSACTION_TYPE
    AND NVL(trd.UPI_DELIVERY_TYPE,' ') = upi_bundle_fixed_float.UPI_DELIVERY_TYPE
)
LEFT JOIN UPI_ANNA_DSB upi_bundle_fixed_float_swaption_underly ON
(
    -- Cette jointure est valide pour les templates suivants :
    --UPI-103	RATES/OPTION/SWAPTION (for the UPI of the underlying swap)
    NVL(trd.UPI_INSTRUMENT_TYPE || ':' || trd.UPI_PRODUCT,' ') = 'Option:Swaption'
    AND upi_bundle_fixed_float_swaption_underly.UPI_INT_CODE IN
    (
        'Swap:Fixed_Float'
        ,'Swap:Fixed_Float_Zero_Coupon'
        ,'Swap:Fixed_Float_OIS'
    )
    AND 'Swap:' || trd.UPI_PRODUCT_IRS_RULE = upi_bundle_fixed_float_swaption_underly.UPI_INT_CODE
    AND NVL(trd.UPI_ASSET_CLASS,' ') = upi_bundle_fixed_float_swaption_underly.UPI_INT_IDX
    AND NVL(trd.UPI_NOTIONAL_CURR,' ') = upi_bundle_fixed_float_swaption_underly.UPI_NOTIONAL_LEG1_CCY
    AND COALESCE(trd.UPI_REF_RATE,trd.UPI_OTHR_LEG_REF_RATE,' ') = upi_bundle_fixed_float_swaption_underly.UPI_REFERENCE_RATE_LEG1
    AND COALESCE(trd.FLOAT_RESET_FREQ_MULTI_LEG1_NO_FGT,FLOAT_RESET_FREQ_MULTI_LEG2_NO_FGT,' ') = upi_bundle_fixed_float_swaption_underly.UPI_UNDERLYING_INDEX_TERM_VAL
    AND COALESCE(trd.FLOAT_RESET_FREQUENCY_LEG1_NO_FGT,trd.FLOAT_RESET_FREQUENCY_LEG2_NO_FGT,' ') = upi_bundle_fixed_float_swaption_underly.UPI_UNDERLYING_INDEX_TERM_UNT
    AND NVL(trd.NOTIONAL_SCHEDULE,' ') = upi_bundle_fixed_float_swaption_underly.UPI_TRANSACTION_TYPE
    AND NVL(trd.UPI_DELIVERY_TYPE,' ') = upi_bundle_fixed_float_swaption_underly.UPI_DELIVERY_TYPE
)
