    upi_fwd_debt.UPI_INT_CODE = 'Forward:Debt'
    AND NVL(trd.UPI_ASSET_CLASS,' ') = upi_fwd_debt.UPI_INT_IDX
    AND NVL(trd.UPI_INSTRUMENT_TYPE || ':' || trd.UPI_PRODUCT,' ') = upi_fwd_debt.UPI_INT_CODE
    AND NVL(trd.UPI_UNDRLNG_INSTR_ISIN,' ') = upi_fwd_debt.UPI_UNDERLYING_INSTR_CODE
    AND NVL(trd.UPI_NOTIONAL_CURR,' ') = upi_fwd_debt.UPI_NOTIONAL_LEG1_CCY
    AND NVL(trd.UPI_RETURN_PAYOUT_TRIGGER,' ') = upi_fwd_debt.UPI_RETURN_OR_PAYOUT_TRIG
    AND NVL(trd.UPI_DELIVERY_TYPE,' ') = upi_fwd_debt.UPI_DELIVERY_TYPE
);

   COMMENT ON TABLE "TMF_SERVICES"."VW_CFTC_TR_RECON_IRD"  IS 'View that contains the logic for the IRD trade'
;
